import React, { useState, useEffect, useRef } from 'react';
import { Page, Message, Project, KryptonDocument, Transaction, KryptonNotification, UserProfile } from '../types';
import { FIKO_ONBOARDING_PROMPT, GATE_THEMES, MOCK_CLIENT_PROJECT, MOCK_CLIENT_DOCS, MOCK_NOTIFICATIONS } from '../constants';
import { GoogleGenAI } from '@google/genai';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Hexagon, Activity, Clock, ShieldCheck, FileText, MessageSquare, 
  Bell, Rocket, Zap, Send, Bot, User, LayoutDashboard, LogOut, Download, 
  Target, TrendingUp, Sparkles, CreditCard, CheckCircle2, ChevronRight, 
  History, Building2, AlertCircle, Eye, Sliders, CheckSquare, Square, Info, 
  ArrowRight, Filter, MoreHorizontal, ExternalLink, Loader2
} from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid } from 'recharts';

interface ClientDashboardPageProps {
  onNavigate: (p: Page) => void;
  gate: string;
}

const ClientDashboardPage: React.FC<ClientDashboardPageProps> = ({ onNavigate, gate }) => {
  const theme = GATE_THEMES[gate] || GATE_THEMES.MARS;
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'overview' | 'project' | 'documents' | 'billing' | 'chat' | 'notifications'>('overview');

  const [project, setProject] = useState<Project>(MOCK_CLIENT_PROJECT);
  const [notifications, setNotifications] = useState<KryptonNotification[]>(MOCK_NOTIFICATIONS);
  const [messages, setMessages] = useState<Message[]>([]);
  const [fikoInsight, setFikoInsight] = useState<string>("Initialisation de la liaison neurale...");

  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const performanceData = [
    { name: '01', value: 400 }, { name: '02', value: 300 }, { name: '03', value: 600 },
    { name: '04', value: 800 }, { name: '05', value: 700 }, { name: '06', value: 1100 },
    { name: '07', value: 900 }
  ];

  useEffect(() => {
    const timer = setTimeout(() => {
      setLoading(false);
      generateInitialFikoInsight();

      const savedMsgs = localStorage.getItem(`krypton_fiko_history_${gate}`);
      if (savedMsgs) setMessages(JSON.parse(savedMsgs));
      else {
          setMessages([{
              role: 'model',
              text: `Bonjour. Votre cockpit stratégique Porte ${gate} est opérationnel. Vos nodes IA sont en phase de synchronisation. Avez-vous besoin d'un rapport sur les premières données ingérées ?`,
              timestamp: new Date().toLocaleTimeString()
          }]);
      }
    }, 1800);
    return () => clearTimeout(timer);
  }, [gate]);

  useEffect(() => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
    if (messages.length > 0) {
        localStorage.setItem(`krypton_fiko_history_${gate}`, JSON.stringify(messages));
    }
  }, [messages, isTyping]);

  const generateInitialFikoInsight = async () => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Génère un diagnostic stratégique ultra-court (1 phrase) pour un dashboard client. Porte: ${gate}, Statut: ${project.status}, Progression: ${project.progress}%. Ton : Expert senior, calme.`,
        config: { systemInstruction: FIKO_ONBOARDING_PROMPT }
      });
      setFikoInsight(response.text || "Monitoring neural actif. Aucun écart détecté.");
    } catch (e) {
      setFikoInsight("Liaison FIKO stable. Diagnostic nominal en cours.");
    }
  };

  const handleSendChat = async () => {
    if (!input.trim() || isTyping) return;
    const userMsg = input;
    setInput('');
    const newMsgs = [...messages, { role: 'user', text: userMsg, timestamp: new Date().toLocaleTimeString() }] as Message[];
    setMessages(newMsgs);
