function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

enum FikoState {
  INITIALIZING,
  AXE_OBJECTIF,
  AXE_SITUATION,
  AXE_FRICTIONS,
  AXE_IMPACT,
  AXE_URGENCE,
  AXE_COMPLEXITE,
  RECOMMANDATION,
  GATE_OPENING
}

interface SmartAction {
  label: string;
  value: string;
  boost: number;
}

interface FikoPageProps {
  onNavigate: (p: Page) => void;
  onOpenGate?: (gate: string) => void; // New prop for App integration
}

const FikoPage: React.FC<FikoPageProps> = ({ onNavigate, onOpenGate }) => {
  const [state, setState] = useState<FikoState>(FikoState.INITIALIZING);
  const [displayedText, setDisplayedText] = useState("");
  const [isTyping, setIsTyping] = useState(false);
  const [maturityScore, setMaturityScore] = useState(10);
  const [voiceEnabled, setVoiceEnabled] = useState(true);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [recommendedGate, setRecommendedGate] = useState<string | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);
  const currentSourceRef = useRef<AudioBufferSourceNode | null>(null);

  const scripts: Record<FikoState, { text: string; actions: SmartAction[] }> = {
    [FikoState.INITIALIZING]: {
      text: "Liaison FIKO CORE établie. Diagnostic stratégique prêt.",
      actions: []
    },
    [FikoState.AXE_OBJECTIF]: {
      text: "Bienvenue. Je suis FIKO. Avant d'avancer, dites-moi : qu'est-ce que vous cherchez réellement à transformer dans votre business aujourd'hui ?",
      actions: [
        { label: "💰 Croissance & Clients", value: "growth", boost: 15 },
        { label: "⚙️ Efficacité & Gestion", value: "ops", boost: 15 },
        { label: "🚀 Domination Marché", value: "domination", boost: 20 }
      ]
    },
    [FikoState.AXE_SITUATION]: {
      text: "Je vois. Comment votre infrastructure actuelle gère-t-elle cette priorité en ce moment ?",
      actions: [
        { label: "Processus Manuel", value: "manual", boost: 10 },
        { label: "Outils Disparates", value: "messy", boost: 15 },
        { label: "Système Obsolete", value: "old", boost: 20 }
      ]
    },
    [FikoState.AXE_FRICTIONS]: {
      text: "C'est un point critique. Qu'est-ce qui vous fait perdre le plus de temps ou d'opportunités actuellement ?",
      actions: [
        { label: "Qualification Leads", value: "leads", boost: 20 },
        { label: "Relances Client", value: "followup", boost: 15 },
        { label: "Surcharge Administrative", value: "admin", boost: 15 }
      ]
    },
    [FikoState.AXE_IMPACT]: {
      text: "Regardons la réalité. Si rien ne change dans 6 mois, quel sera le coût concret pour votre entreprise ?",
      actions: [
        { label: "Perte de C.A. Directe", value: "money", boost: 15 },
        { label: "Stagnation Totale", value: "plateau", boost: 20 },
        { label: "Épuisement Équipes", value: "burnout", boost: 10 }
      ]
    },
    [FikoState.AXE_URGENCE]: {
      text: "L'impact est identifié. À quel point la résolution de ce blocage est-elle prioritaire pour votre direction ?",
      actions: [
        { label: "Priorité Absolue", value: "urgent", boost: 25 },
        { label: "Sous 30 jours", value: "medium", boost: 10 },
        { label: "En observation", value: "low", boost: 5 }
      ]
    },
    [FikoState.AXE_COMPLEXITE]: {
      text: "Dernière précision : parle-t-on d'un besoin ponctuel ou d'une infrastructure robuste pour dominer votre secteur ?",
      actions: [
        { label: "Simple & Rapide", value: "light", boost: 10 },
        { label: "Système Structuré", value: "robust", boost: 15 },
        { label: "Souveraineté IA", value: "total", boost: 20 }
      ]
    },
    [FikoState.RECOMMANDATION]: {
      text: `D'après notre échange, la PORTE ${recommendedGate || 'MARS'} est la seule décision logique pour vous. Je vais vous expliquer pourquoi.`,
      actions: [
        { label: "Détaillez la stratégie", value: "explain", boost: 5 }
      ]
    },
    [FikoState.GATE_OPENING]: {
      text: "C'est la décision d'un dirigeant averti. Je vous ouvre l'accès au Portal Gate immédiatement.",
      actions: [
        { label: "FRANCHIR LA PORTE", value: "enter", boost: 5 }
      ]
    }
  };

  const speakWithGemini = useCallback(async (text: string) => {
    if (!voiceEnabled) return;
    if (currentSourceRef.current) currentSourceRef.current.stop();

    setIsSpeaking(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: `Instruction système FIKO : Autorité calme, expert senior, ton posé. Texte : ${text}` }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: 'Kore' },
            },
          },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) {
        if (!audioContextRef.current) {
          audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        }
        const audioBuffer = await decodeAudioData(decode(base64Audio), audioContextRef.current, 24000, 1);
        const source = audioContextRef.current.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(audioContextRef.current.destination);
        source.onended = () => { setIsSpeaking(false); currentSourceRef.current = null; };
        currentSourceRef.current = source;
        source.start();
      }
    } catch (error) {
      console.error("TTS Gemini Error:", error);
      setIsSpeaking(false);
    }
  }, [voiceEnabled]);

  useEffect(() => {
    if (state === FikoState.INITIALIZING) {
      setTimeout(() => setState(FikoState.AXE_OBJECTIF), 2200);
      return;
    }

    const currentScript = scripts[state];
    if (!currentScript) return;

    setDisplayedText("");
    setIsTyping(true);
    speakWithGemini(currentScript.text);

    let i = 0;
    const interval = setInterval(() => {
      setDisplayedText((prev) => prev + currentScript.text.charAt(i));
      i++;
      if (i >= currentScript.text.length) {
        clearInterval(interval);
        setIsTyping(false);
      }
