    return () => {
      clearInterval(interval);
      if (currentSourceRef.current) currentSourceRef.current.stop();
    };
  }, [state, speakWithGemini, recommendedGate]);

  const handleAction = (action: SmartAction) => {
    const nextScore = Math.min(100, maturityScore + action.boost);
