      setState(FikoState.RECOMMANDATION);
      return;
    }

    switch(state) {
      case FikoState.AXE_OBJECTIF: setState(FikoState.AXE_SITUATION); break;
      case FikoState.AXE_SITUATION: setState(FikoState.AXE_FRICTIONS); break;
      case FikoState.AXE_FRICTIONS: setState(FikoState.AXE_IMPACT); break;
      case FikoState.AXE_IMPACT: setState(FikoState.AXE_URGENCE); break;
      case FikoState.AXE_URGENCE: setState(FikoState.AXE_COMPLEXITE); break;
