      <header className="relative z-50 px-10 h-24 flex items-center justify-between border-b border-white/5 bg-black/40 backdrop-blur-xl">
        <button onClick={() => onNavigate(Page.HOME)} className="flex items-center gap-4 text-[10px] font-black uppercase tracking-[0.5em] text-slate-500 hover:text-white transition-all">
          <ArrowLeft size={16} /> Abandonner
        </button>
        <div className="flex items-center gap-10">
           <div className={`size-3 rounded-full ${isSpeaking ? 'bg-[#E10600] animate-pulse' : 'bg-slate-700'}`}></div>
           <button onClick={() => setVoiceEnabled(!voiceEnabled)} className={`size-12 rounded-full flex items-center justify-center border ${voiceEnabled ? 'border-[#E10600] text-[#E10600]' : 'border-white/10 text-slate-500'}`}>
             {voiceEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}
           </button>
        </div>
      </header>

