                <p className="text-[7px] font-black text-[#E10600] uppercase tracking-widest">SUPER_ADMIN</p>
             </div>
          </div>
          <button onClick={onLogout} className="w-full flex items-center gap-4 px-4 text-slate-500 hover:text-red-500 transition-all text-[9px] font-black uppercase tracking-widest">
            <LogOut size={16} /> Déconnexion
