  onNavigate: (p: Page) => void;
  user: UserProfile | null;
  onLogout: () => void;
}

type AdminModule = 'overview' | 'fiko-control' | 'ml-control' | 'explainability' | 'insights' | 'admins' | 'security' | 'reports' | 'clients-prospects' | 'relances-suivi';

const AdminDashboardPage: React.FC<AdminDashboardPageProps> = ({ onNavigate, user, onLogout }) => {
  const [loading, setLoading] = useState(true);
  const [activeModule, setActiveModule] = useState<AdminModule>('overview');
  const [fikoStatus, setFikoStatus] = useState<'active' | 'paused' | 'dead'>('active');
  const [globalKillSwitch, setGlobalKillSwitch] = useState(false);
  const [models, setModels] = useState<MLModel[]>(MOCK_MODELS);

  // Clients & Prospects Module States
  const [leadSearch, setLeadSearch] = useState('');
  const [selectedLeads, setSelectedLeads] = useState<string[]>([]);
  const [leadFilterStatus, setLeadFilterStatus] = useState<'all' | 'prospect' | 'client'>('all');

  // Relances Module States
  const [autoFollowUp, setAutoFollowUp] = useState(true);
  const [generatingMessage, setGeneratingMessage] = useState(false);
  const [currentFikoMessage, setCurrentFikoMessage] = useState('');

  const isSuperAdmin = user?.role === UserRole.SUPER_ADMIN;

  useEffect(() => {
    if (user?.role !== UserRole.SUPER_ADMIN && user?.role !== UserRole.ADMIN) {
      onNavigate(Page.HOME);
    }
    const timer = setTimeout(() => setLoading(false), 1000);
    return () => clearTimeout(timer);
  }, [user, onNavigate]);

  const filteredLeads = LEADS.filter(l => {
    const matchesSearch = l.entity.toLowerCase().includes(leadSearch.toLowerCase()) || (l.email && l.email.toLowerCase().includes(leadSearch.toLowerCase()));
    const matchesStatus = leadFilterStatus === 'all' || (leadFilterStatus === 'prospect' ? l.status !== 'client' : l.status === 'client');
    return matchesSearch && matchesStatus;
  });

  const generateFikoFollowUp = async (lead: Lead) => {
    setGeneratingMessage(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Génère un message de relance court et stratégique pour ${lead.entity}. 
                   Score Priorité: ${lead.priorityScore}, Moment: ${lead.buyingMoment}.
                   Contexte: Il a montré de l'intérêt pour la Porte ${lead.gate}. 
                   Ton: Direct, expert, pas insistant mais axé sur le coût de l'opportunité.`,
        config: { systemInstruction: FIKO_MASTER_CLOSER_PROMPT }
      });
      setCurrentFikoMessage(response.text || "Diagnostic prêt pour discussion.");
    } catch (e) {
