```tsx
"use client";
import { useEffect, useState } from "react";
import { collection, onSnapshot } from "firebase/firestore";
import { db } from "@/lib/firebase";
import { requireSuperAdmin } from "@/lib/auth-rbac";
import RelanceModal from "./RelanceModal";

export default function ClientsProspects() {
  const [rows, setRows] = useState<any[]>([]);
  const [selected, setSelected] = useState<any[]>([]);
  const [open, setOpen] = useState(false);

  useEffect(() => {
    requireSuperAdmin(() => {
      onSnapshot(collection(db, "leads"), (snap) => {
        setRows(
          snap.docs.map((d) => ({ id: d.id, ...d.data() }))
        );
      });
    });
  }, []);

  return (
    <div>
      <h1 className="text-2xl font-bold mb-6">
        Clients & Prospects
      </h1>

      <button
        onClick={() => setOpen(true)}
        disabled={selected.length === 0}
        className="mb-4 bg-green-600 px-4 py-2 rounded"
      >
        Relancer ({selected.length})
      </button>

      <table className="w-full text-sm border">
        <thead className="bg-zinc-900">
          <tr>
            <th />
            <th>Nom</th>
            <th>Email</th>
            <th>Type</th>
            <th>Porte</th>
            <th>Statut</th>
            <th>Priority</th>
            <th>Buying</th>
            <th>Dernière interaction</th>
            <th>Action IA</th>
          </tr>
        </thead>

        <tbody>
          {rows.map((r) => (
            <tr key={r.id} className="border-t">
              <td>
                <input
                  type="checkbox"
                  onChange={(e) =>
                    setSelected((prev) =>
                      e.target.checked
                        ? [...prev, r]
                        : prev.filter((x) => x.id !== r.id)
                    )
                  }
                />
              </td>
              <td>{r.name}</td>
              <td>{r.email}</td>
              <td>{r.type}</td>
              <td>{r.port}</td>
              <td>{r.status}</td>
              <td>{r.priority_score}</td>
              <td>{r.buying_window}</td>
              <td>{r.last_interaction}</td>
              <td>
                <span className="text-green-400">
                  {r.recommended_action}
                </span>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      {open && (
        <RelanceModal
          targets={selected}
          onClose={() => setOpen(false)}
        />
      )}
    </div>
  );
}
```

---

# 2️⃣ MODALE DE RELANCE (MANUELLE + FIKO)

### `/clients-prospects/RelanceModal.tsx`

```tsx
"use client";
import { useState } from "react";
import { httpsCallable } from "firebase/functions";
import { functions } from "@/lib/firebase";

export default function RelanceModal({ targets, onClose }: any) {
  const [channel, setChannel] = useState("email");
  const [tone, setTone] = useState("strategique");

  const sendRelance = async () => {
    const call = httpsCallable(functions, "sendRelance");
    await call({
      targets,
      channel,
      tone,
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/70 flex items-center justify-center">
      <div className="bg-zinc-900 p-6 rounded w-[420px]">
        <h2 className="text-xl mb-4">Relance FIKO</h2>

        <label>Canal</label>
        <select
          className="w-full mb-3"
          onChange={(e) => setChannel(e.target.value)}
        >
          <option value="email">Email</option>
          <option value="dashboard">Notification</option>
          <option value="fiko">Message FIKO</option>
        </select>

        <label>Ton</label>
        <select
          className="w-full mb-4"
          onChange={(e) => setTone(e.target.value)}
        >
          <option value="soft">Soft</option>
          <option value="strategique">Stratégique</option>
          <option value="direct">Direct</option>
        </select>

        <button
          onClick={sendRelance}
          className="bg-green-600 w-full py-2 rounded"
        >
          Lancer la relance
        </button>

        <button
          onClick={onClose}
          className="mt-2 text-sm opacity-70"
        >
          Annuler
        </button>
      </div>
    </div>
  );
}
```

