const AdminDashboardPage: React.FC<AdminDashboardPageProps> = ({ onNavigate, user, onLogout }) => {
  const [loading, setLoading] = useState(true);
  const [activeModule, setActiveModule] = useState<AdminModule>('overview');
  const [fikoStatus, setFikoStatus] = useState<'active' | 'paused' | 'dead'>('active');
  const [globalKillSwitch, setGlobalKillSwitch] = useState(false);

  // Clients & Prospects States
  const [leadSearch, setLeadSearch] = useState('');
  const [selectedLeadIds, setSelectedLeadIds] = useState<string[]>([]);
  const [statusFilter, setStatusFilter] = useState<'all' | 'client' | 'prospect'>('all');

  // Follow-up States
  const [followUps, setFollowUps] = useState<FollowUpRecord[]>(FOLLOW_UPS);
  const [autoFollowUpActive, setAutoFollowUpActive] = useState(true);
  const [generatingFikoMsg, setGeneratingFikoMsg] = useState(false);
  const [fikoSuggestion, setFikoSuggestion] = useState("");
  const [selectedChannel, setSelectedChannel] = useState<'email' | 'dashboard' | 'fiko' | 'whatsapp'>('email');
  const [selectedTone, setSelectedTone] = useState<'soft' | 'strategique' | 'direct'>('strategique');
  const [selectedScenario, setSelectedScenario] = useState<FollowUpScenario>('URGENCE_STRATEGIQUE');

  useEffect(() => {
    if (user?.role !== UserRole.SUPER_ADMIN && user?.role !== UserRole.ADMIN) {
      onNavigate(Page.HOME);
    }
    const timer = setTimeout(() => setLoading(false), 1000);
    return () => clearTimeout(timer);
  }, [user, onNavigate]);

  const filteredLeads = LEADS.filter(l => {
    const matchesSearch = l.entity.toLowerCase().includes(leadSearch.toLowerCase()) || l.email.toLowerCase().includes(leadSearch.toLowerCase());
    const matchesStatus = statusFilter === 'all' || (statusFilter === 'client' ? l.status === 'client' : l.status !== 'client');
    return matchesSearch && matchesStatus;
  });

  const toggleLeadSelection = (id: string) => {
    setSelectedLeadIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const generateFikoRelance = async () => {
    if (selectedLeadIds.length === 0) return;
    setGeneratingFikoMsg(true);
    setFikoSuggestion("");

    const target = LEADS.find(l => l.id === selectedLeadIds[0])!;

    const scenarioPrompts: Record<FollowUpScenario, string> = {
      'ABANDON_TUNNEL': "Le prospect a quitté le tunnel à une étape clé. Sois empathique et propose de l'aide sans forcer.",
      'PAIEMENT_ATTENTE': "Paiement non reçu après 48h. Rappelle que l'infrastructure est prête au lancement immédiat dès validation.",
      'CHAUD_SILENCIEUX': "Prospect avec score > 75 mais muet depuis 72h. Reprends le point de douleur identifié.",
      'CLIENT_RALENTI': "Client actif dont le projet ne progresse plus. Propose un point stratégique de déblocage.",
      'URGENCE_STRATEGIQUE': "Le timing est critique. Accélère la décision en soulignant le coût d'opportunité."
    };

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Génère une relance pour ${target.entity}. 
                   Scénario : ${selectedScenario}. ${scenarioPrompts[selectedScenario]}
                   Contexte : Porte ${target.gate}, Score Priorité: ${target.priorityScore}, Risque: ${target.riskScore}%.
                   Ton souhaité : ${selectedTone}. Canal : ${selectedChannel}. 
                   Important : Ne répète jamais les messages précédents.`,
        config: { systemInstruction: FIKO_MASTER_CLOSER_PROMPT }
      });
      setFikoSuggestion(response.text || "Diagnostic prêt. Souhaitez-vous déclencher la séquence ?");
    } catch (e) {
      setFikoSuggestion("Liaison FIKO instable. Message de secours : Votre projet Krypton est en attente d'action. Sommes-nous alignés ?");
    } finally {
      setGeneratingFikoMsg(false);
    }
  };

  const sendManualRelance = () => {
    if (!fikoSuggestion || selectedLeadIds.length === 0) return;
    const target = LEADS.find(l => l.id === selectedLeadIds[0])!;
    const newRecord: FollowUpRecord = {
      id: `F-${Date.now()}`,
      targetId: target.id,
      targetName: target.entity,
      channel: selectedChannel,
      scenario: selectedScenario,
      message: fikoSuggestion,
      sentAt: new Date().toISOString(),
      status: 'sent',
      type: 'manual'
    };
    setFollowUps([newRecord, ...followUps]);
    setSelectedLeadIds([]);
    setFikoSuggestion("");
    alert("Séquence transmise via le protocole Krypton.");
  };

  if (loading) return (
    <div className="min-h-screen bg-[#0B0B0F] flex flex-col items-center justify-center gap-8">
      <div className="relative">
        <Hexagon size={100} className="text-[#E10600] animate-[spin_10s_linear_infinite]" strokeWidth={1} />
        <div className="absolute inset-0 flex items-center justify-center">
          <Crown size={40} className="text-[#E10600] animate-pulse" />
        </div>
      </div>
      <p className="text-[10px] font-black uppercase tracking-[0.6em] text-[#E10600]">INITIALISATION COCKPIT SUPER ADMIN...</p>
    </div>
  );

  const sidebarLinks = [
    { id: 'overview', label: 'Executive Overview', icon: <LayoutDashboard size={18} /> },
    { id: 'clients-prospects', label: 'Clients & Prospects', icon: <Users size={18} />, badge: LEADS.length.toString() },
    { id: 'relances-suivi', label: 'Relances & Suivi', icon: <History size={18} /> },
    { id: 'fiko-control', label: 'FIKO Neural Core', icon: <Bot size={18} /> },
    { id: 'ml-control', label: 'Vertex AI Nodes', icon: <Brain size={18} /> },
    { id: 'explainability', label: 'Logic XAI', icon: <Eye size={18} /> },
    { id: 'insights', label: 'Looker Insights', icon: <TrendingUp size={18} /> },
    { id: 'security', label: 'System Security', icon: <ShieldCheck size={18} /> },
    { id: 'reports', label: 'Export Engine', icon: <FileText size={18} /> },
  ];

  const getRiskColor = (score: number) => {
    if (score >= 70) return 'text-red-500 bg-red-500/10 border-red-500/30';
    if (score >= 40) return 'text-orange-500 bg-orange-500/10 border-orange-500/30';
    return 'text-emerald-500 bg-emerald-500/10 border-emerald-500/30';
  };

  return (
    <div className="min-h-screen bg-[#0B0B0F] text-white flex overflow-hidden selection:bg-[#E10600]">

      {/* 🛠 SIDEBAR */}
      <aside className="w-80 bg-[#0E0E12] border-r border-white/5 flex flex-col z-50">
        <div className="p-8 border-b border-white/5 flex items-center gap-4">
          <div className="size-10 bg-[#E10600] text-white rounded-sm flex items-center justify-center shadow-lg shadow-red-900/20">
            <Crown size={20} />
          </div>
          <div>
            <p className="font-black uppercase tracking-tighter text-xl leading-none">KRYPTON <span className="text-[#E10600]">HQ</span></p>
            <p className="text-[8px] font-black text-slate-600 uppercase tracking-[0.4em] mt-1">Super Admin v1.0</p>
          </div>
        </div>

        <nav className="flex-grow py-8 px-4 space-y-1 overflow-y-auto custom-scrollbar">
          {sidebarLinks.map(item => (
            <button 
              key={item.id} 
              onClick={() => setActiveModule(item.id as AdminModule)} 
              className={`w-full flex items-center gap-4 px-6 py-4 rounded-sm transition-all group relative ${
                activeModule === item.id ? 'bg-[#E10600] text-white shadow-xl' : 'text-slate-500 hover:text-white hover:bg-white/5'
              }`}
            >
              <span>{item.icon}</span>
              <span className="text-[10px] font-bold uppercase tracking-widest text-left flex-grow">{item.label}</span>
              {item.badge && <span className="text-[8px] font-black bg-white/10 px-2 py-0.5 rounded-sm">{item.badge}</span>}
              {activeModule === item.id && <ChevronRight size={14} className="animate-pulse" />}
            </button>
          ))}
        </nav>

        <div className="p-8 border-t border-white/5 space-y-6">
          <div className="flex items-center gap-4 p-4 bg-white/5 rounded-sm">
             <div className="size-8 bg-slate-800 rounded-full flex items-center justify-center text-[10px] font-bold">{user?.firstName[0]}{user?.lastName[0]}</div>
             <div className="flex-grow overflow-hidden">
                <p className="text-[9px] font-black text-white uppercase truncate">{user?.firstName} {user?.lastName}</p>
                <p className="text-[7px] font-black text-[#E10600] uppercase tracking-widest">{user?.role}</p>
             </div>
