  // Templates States
  const [templates, setTemplates] = useState<FikoTemplate[]>(FIKO_TEMPLATES);
  const [editingTemplate, setEditingTemplate] = useState<FikoTemplate | null>(null);
  const [previewText, setPreviewText] = useState("");
