import React, { useState, useEffect } from 'react';
import { Page, UserProfile, UserRole, Lead, BuyingWindow, MLModel, SecurityLog, FollowUpRecord, LTVClass, FollowUpScenario, FikoTemplate, FikoTone } from '../types';
import { LEADS, MOCK_MODELS, SECURITY_LOGS, FOLLOW_UPS, FIKO_MASTER_CLOSER_PROMPT, GATE_THEMES, FIKO_TEMPLATES } from '../constants';
import { GoogleGenAI } from '@google/genai';
import { 
  AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer, BarChart, Bar, Cell, LineChart, Line
} from 'recharts';
import { 
  Hexagon, Activity, ShieldCheck, LogOut, LayoutDashboard, Crown, TrendingUp, Target, Brain, 
  ShieldAlert, Sliders, Power, History, Users, MoreVertical, Database, Zap, Clock, Eye, Shield, 
  Settings, FileText, Download, User, CheckCircle2, AlertCircle, Loader2, Server, Filter, 
  MoreHorizontal, Info, Search, Key, ChevronRight, AlertTriangle, RefreshCw, Mail, MessageSquare, 
  Trash2, Send, CheckSquare, Square, Smartphone, ArrowRight, Bot, Sparkles, Plus, BookOpen, Wand2
} from 'lucide-react';

interface AdminDashboardPageProps {
  onNavigate: (p: Page) => void;
  user: UserProfile | null;
  onLogout: () => void;
}

type AdminModule = 'overview' | 'clients-prospects' | 'relances-suivi' | 'fiko-templates' | 'fiko-control' | 'ml-control' | 'security' | 'reports';

const AdminDashboardPage: React.FC<AdminDashboardPageProps> = ({ onNavigate, user, onLogout }) => {
  const [loading, setLoading] = useState(true);
  const [activeModule, setActiveModule] = useState<AdminModule>('overview');
  const [fikoStatus, setFikoStatus] = useState<'active' | 'paused' | 'dead'>('active');
  const [globalKillSwitch, setGlobalKillSwitch] = useState(false);

  // Clients & Prospects States
  const [leadSearch, setLeadSearch] = useState('');
  const [selectedLeadIds, setSelectedLeadIds] = useState<string[]>([]);
  const [statusFilter, setStatusFilter] = useState<'all' | 'client' | 'prospect'>('all');

  // Templates States
  const [templates, setTemplates] = useState<FikoTemplate[]>(FIKO_TEMPLATES);
  const [editingTemplate, setEditingTemplate] = useState<FikoTemplate | null>(null);
  const [previewText, setPreviewText] = useState("");
  const [isPreviewLoading, setIsPreviewLoading] = useState(false);
  const [previewTone, setPreviewTone] = useState<FikoTone>('strategique');
  const [previewLeadId, setPreviewLeadId] = useState<string>(LEADS[0].id);

  // Fix: Added missing toggleLeadSelection function
  const toggleLeadSelection = (id: string) => {
    setSelectedLeadIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  useEffect(() => {
    if (user?.role !== UserRole.SUPER_ADMIN && user?.role !== UserRole.ADMIN) {
      onNavigate(Page.HOME);
    }
    const timer = setTimeout(() => setLoading(false), 1000);
    return () => clearTimeout(timer);
  }, [user, onNavigate]);

  const filteredLeads = LEADS.filter(l => {
    const matchesSearch = l.entity.toLowerCase().includes(leadSearch.toLowerCase()) || l.email.toLowerCase().includes(leadSearch.toLowerCase());
    const matchesStatus = statusFilter === 'all' || (statusFilter === 'client' ? l.status === 'client' : l.status !== 'client');
    return matchesSearch && matchesStatus;
  });

  const generatePreview = async (template: FikoTemplate) => {
    setIsPreviewLoading(true);
    setPreviewText("");
    const targetLead = LEADS.find(l => l.id === previewLeadId) || LEADS[0];

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Génère un message de relance final basé sur ce template racine : "${template.basePrompt}".
                   TON SOUHAITÉ : ${previewTone}.
                   CONTEXTE PROSPECT : Nom=${targetLead.entity}, Porte=${targetLead.gate}, Score Priorité=${targetLead.priorityScore}%, Moment=${targetLead.buyingMoment}.
                   CONSIGNE : Utilise le ton demandé avec autorité. Personnalise avec les infos prospect. Sois percutant.`,
        config: { systemInstruction: FIKO_MASTER_CLOSER_PROMPT }
      });
      setPreviewText(response.text || "Erreur de génération.");
    } catch (e) {
      setPreviewText("Échec de l'inférence neuronale. Vérifiez la liaison API.");
    } finally {
      setIsPreviewLoading(false);
    }
  };

  const getRiskColor = (score: number) => {
    if (score >= 70) return 'text-red-500 bg-red-500/10 border-red-500/30';
    if (score >= 40) return 'text-orange-500 bg-orange-500/10 border-orange-500/30';
    return 'text-emerald-500 bg-emerald-500/10 border-emerald-500/30';
  };

  if (loading) return (
    <div className="min-h-screen bg-[#0B0B0F] flex flex-col items-center justify-center gap-8">
      <div className="relative">
        <Hexagon size={100} className="text-[#E10600] animate-[spin_10s_linear_infinite]" strokeWidth={1} />
        <div className="absolute inset-0 flex items-center justify-center">
          <Crown size={40} className="text-[#E10600] animate-pulse" />
        </div>
      </div>
      <p className="text-[10px] font-black uppercase tracking-[0.6em] text-[#E10600]">INITIALISATION COCKPIT SUPER ADMIN...</p>
    </div>
  );

  const sidebarLinks = [
    { id: 'overview', label: 'Executive Overview', icon: <LayoutDashboard size={18} /> },
    { id: 'clients-prospects', label: 'Clients & Prospects', icon: <Users size={18} />, badge: LEADS.length.toString() },
    { id: 'relances-suivi', label: 'Relances & Suivi', icon: <History size={18} /> },
    { id: 'fiko-templates', label: 'Templates FIKO™', icon: <BookOpen size={18} /> },
    { id: 'fiko-control', label: 'IA & FIKO Engine', icon: <Bot size={18} /> },
    { id: 'ml-control', label: 'Machine Learning', icon: <Brain size={18} /> },
    { id: 'security', label: 'Node Security', icon: <ShieldCheck size={18} /> },
    { id: 'reports', label: 'Export Engine', icon: <FileText size={18} /> },
  ];

  return (
    <div className="min-h-screen bg-[#0B0B0F] text-white flex overflow-hidden selection:bg-[#E10600]">

      {/* 🛠 SIDEBAR */}
      <aside className="w-80 bg-[#0E0E12] border-r border-white/5 flex flex-col z-50">
        <div className="p-8 border-b border-white/5 flex items-center gap-4">
          <div className="size-10 bg-[#E10600] text-white rounded-sm flex items-center justify-center shadow-lg shadow-red-900/20">
            <Crown size={20} />
          </div>
          <div>
            <p className="font-black uppercase tracking-tighter text-xl leading-none">KRYPTON <span className="text-[#E10600]">HQ</span></p>
            <p className="text-[8px] font-black text-slate-600 uppercase tracking-[0.4em] mt-1">Super Admin v1.0</p>
          </div>
        </div>

        <nav className="flex-grow py-8 px-4 space-y-1 overflow-y-auto custom-scrollbar">
          {sidebarLinks.map(item => (
            <button 
              key={item.id} 
              onClick={() => setActiveModule(item.id as AdminModule)} 
              className={`w-full flex items-center gap-4 px-6 py-4 rounded-sm transition-all group relative ${
                activeModule === item.id ? 'bg-[#E10600] text-white shadow-xl shadow-red-900/20' : 'text-slate-500 hover:text-white hover:bg-white/5'
              }`}
            >
              <span>{item.icon}</span>
              <span className="text-[10px] font-bold uppercase tracking-widest text-left flex-grow">{item.label}</span>
              {item.badge && <span className="text-[8px] font-black bg-white/10 px-2 py-0.5 rounded-sm">{item.badge}</span>}
              {activeModule === item.id && <ChevronRight size={14} className="animate-pulse" />}
            </button>
          ))}
