## 1️⃣ PAGE PRINCIPALE

### `/risk-relance/page.tsx`

```tsx
"use client";
import { useEffect, useState } from "react";
import { requireSuperAdmin } from "@/lib/auth-rbac";
import { collection, onSnapshot } from "firebase/firestore";
import { db } from "@/lib/firebase";

import RiskKPIs from "./RiskKPIs";
import RiskTable from "./RiskTable";
import RelanceTimeline from "./RelanceTimeline";
import ActionPanel from "./ActionPanel";

export default function RiskRelancePage() {
  const [risks, setRisks] = useState<any[]>([]);
  const [relances, setRelances] = useState<any[]>([]);

  useEffect(() => {
    requireSuperAdmin(() => {
      onSnapshot(collection(db, "risk_profiles"), snap =>
        setRisks(snap.docs.map(d => ({ id: d.id, ...d.data() })))
      );

      onSnapshot(collection(db, "relances"), snap =>
        setRelances(snap.docs.map(d => ({ id: d.id, ...d.data() })))
      );
    });
  }, []);

  return (
    <div className="space-y-8">
      <h1 className="text-2xl font-bold">
        Risk & Relance Intelligence
      </h1>

      <RiskKPIs risks={risks} relances={relances} />

      <div className="grid grid-cols-3 gap-6">
        <div className="col-span-2">
          <RiskTable risks={risks} />
        </div>
        <div>
          <ActionPanel />
        </div>
      </div>

      <RelanceTimeline relances={relances} />
    </div>
  );
}
```

---

## 2️⃣ KPIs RISQUE & RELANCE

### `/RiskKPIs.tsx`

```tsx
export default function RiskKPIs({ risks, relances }: any) {
  const critical = risks.filter(r => r.risk_level === "CRITIQUE").length;
  const medium = risks.filter(r => r.risk_level === "MOYEN").length;
  const recovered = relances.filter(r => r.impact === "RECOVERED").length;

  return (
    <div className="grid grid-cols-4 gap-4">
      <KPI label="Clients à risque critique" value={critical} />
      <KPI label="Risque moyen" value={medium} />
      <KPI label="Relances actives" value={relances.length} />
      <KPI label="Ventes récupérées" value={recovered} />
    </div>
  );
}

const KPI = ({ label, value }: any) => (
  <div className="bg-zinc-900 p-4 rounded">
    <p className="text-sm opacity-70">{label}</p>
    <p className="text-2xl font-bold">{value}</p>
  </div>
);
```

