```tsx
import RelanceButton from "./RelanceButton";

export default function RiskTable({ risks }: any) {
  return (
    <table className="w-full text-sm border">
      <thead className="bg-zinc-900">
        <tr>
          <th>Client</th>
          <th>Porte</th>
          <th>Risque</th>
          <th>Probabilité ML</th>
          <th>Fenêtre</th>
          <th>Dernière action</th>
          <th>Action</th>
        </tr>
      </thead>
      <tbody>
        {risks.map((r: any) => (
          <tr key={r.id} className="border-t">
            <td>{r.email}</td>
            <td>{r.port}</td>
            <td>
              <span className={
                r.risk_level === "CRITIQUE"
                  ? "text-red-500"
                  : r.risk_level === "MOYEN"
                  ? "text-orange-400"
                  : "text-green-400"
              }>
                {r.risk_level}
              </span>
            </td>
            <td>{Math.round(r.ml_probability * 100)}%</td>
            <td>{r.risk_window}</td>
