## 5️⃣ PANNEAU ACTION SUPER ADMIN

### `/ActionPanel.tsx`

```tsx
"use client";
import { httpsCallable } from "firebase/functions";
import { functions } from "@/lib/firebase";

export default function ActionPanel() {
  const toggleRelance = async (state: boolean) => {
    const call = httpsCallable(functions, "toggleAutoRelance");
    await call({ enabled: state });
  };

  return (
    <div className="bg-zinc-900 p-4 rounded space-y-4">
      <h3 className="font-bold">Contrôle Relances</h3>

      <button
        className="bg-green-600 w-full py-2"
        onClick={() => toggleRelance(true)}
      >
        Activer relances auto
      </button>

      <button
        className="bg-red-600 w-full py-2"
        onClick={() => toggleRelance(false)}
      >
        Désactiver relances auto
      </button>
    </div>
  );
}
```

