import React, { useState, useEffect, useMemo } from 'react';
import { 
  Page, UserProfile, UserRole, Lead, BuyingWindow, FikoAutopilotStatus, AutopilotDecision 
} from '../types';
import { 
  LEADS, FIKO_AUTOPILOT_PROMPT, FIKO_MASTER_CLOSER_PROMPT, GATE_THEMES 
} from '../constants';
import { GoogleGenAI } from '@google/genai';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Hexagon, Activity, ShieldCheck, LogOut, LayoutDashboard, Crown, TrendingUp, 
  Target, Brain, ShieldAlert, Sliders, Power, History, Users, Zap, 
  Search, ChevronRight, RefreshCw, Bot, Wand2, Terminal, ArrowRight, 
  MessageSquare, Mail, Mic, Eye
} from 'lucide-react';

interface AdminDashboardPageProps {
  onNavigate: (p: Page) => void;
  user: UserProfile | null;
  onLogout: () => void;
}

type AdminModule = 'overview' | 'autopilot' | 'leads' | 'security';

const AdminDashboardPage: React.FC<AdminDashboardPageProps> = ({ onNavigate, user, onLogout }) => {
  const [loading, setLoading] = useState(true);
  const [activeModule, setActiveModule] = useState<AdminModule>('overview');
  const [leads, setLeads] = useState<Lead[]>(LEADS);
  const [isInferenceLoading, setIsInferenceLoading] = useState<string | null>(null);
  const [lastInferenceResult, setLastInferenceResult] = useState<AutopilotDecision | null>(null);

  useEffect(() => {
    if (user?.role !== UserRole.SUPER_ADMIN && user?.role !== UserRole.ADMIN) {
      onNavigate(Page.HOME);
    }
    const timer = setTimeout(() => setLoading(false), 1000);
    return () => clearTimeout(timer);
  }, [user, onNavigate]);

  const stats = useMemo(() => ({
    revenue: "2.84B FCFA",
    autopilotActions: leads.filter(l => l.autopilotState.status === 'INTERVENTION').length,
    criticalRisk: leads.filter(l => l.riskLevel === 'CRITIQUE').length,
    efficiency: "94.2%"
  }), [leads]);

  const runAutopilotInference = async (lead: Lead) => {
    setIsInferenceLoading(lead.id);
    setLastInferenceResult(null);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `ANALYSE DU LEAD :
                   Nom: ${lead.entity}
                   Porte: ${lead.gate}
                   Priority: ${lead.priorityScore}%
                   Risk: ${lead.riskScore}% (${lead.riskLevel})
                   Buying Window: ${lead.buyingMoment}
                   Last Activity: ${new Date(lead.lastInteraction).toLocaleString()}

                   DÉCIDE DE L'ACTION SELON LE PROMPT MASTER.`,
        config: { 
          systemInstruction: FIKO_AUTOPILOT_PROMPT,
          responseMimeType: "application/json"
        }
      });

      const decision: AutopilotDecision = {
        id: `D-${Date.now()}`,
        timestamp: new Date().toISOString(),
        signal: lead.riskLevel === 'CRITIQUE' ? 'HIGH_RISK_SIGNAL' : 'IDLE_SIGNAL',
        status: 'EXECUTED',
        ...JSON.parse(response.text)
      };

      setLastInferenceResult(decision);

      // Update local state
      setLeads(prev => prev.map(l => l.id === lead.id ? {
        ...l,
        autopilotState: {
          ...l.autopilotState,
          status: decision.action === 'SILENCE' ? 'SILENCE_STRATÉGIQUE' : 'INTERVENTION',
          lastDecision: decision,
          sessionHistory: [decision, ...l.autopilotState.sessionHistory]
        }
      } : l));

    } catch (e) {
      console.error("Autopilot Engine Error", e);
    } finally {
      setIsInferenceLoading(null);
    }
  };

  const getStatusColor = (status: FikoAutopilotStatus) => {
    switch(status) {
      case 'INTERVENTION': return 'text-[#E10600] bg-[#E10600]/10 border-[#E10600]/30';
      case 'OBSERVATION': return 'text-emerald-500 bg-emerald-500/10 border-emerald-500/30';
      case 'SILENCE_STRATÉGIQUE': return 'text-slate-500 bg-slate-500/10 border-slate-500/30';
      default: return 'text-white bg-white/10';
    }
  };

  if (loading) return (
    <div className="min-h-screen bg-[#0B0B0F] flex flex-col items-center justify-center gap-8">
      <Hexagon size={100} className="text-[#E10600] animate-spin" strokeWidth={1} />
      <p className="text-[10px] font-black uppercase tracking-[0.6em] text-[#E10600]">SYNCHRONISATION FIKO NEURAL CORE...</p>
    </div>
  );

  return (
    <div className="min-h-screen bg-[#0B0B0F] text-white flex overflow-hidden">

      {/* 🛠 SIDEBAR */}
      <aside className="w-80 bg-[#0E0E12] border-r border-white/5 flex flex-col z-50">
        <div className="p-8 border-b border-white/5 flex items-center gap-4">
          <div className="size-10 bg-[#E10600] text-white rounded-sm flex items-center justify-center shadow-lg"><Crown size={20} /></div>
          <div>
            <p className="font-black uppercase tracking-tighter text-xl leading-none">KRYPTON <span className="text-[#E10600]">HQ</span></p>
            <p className="text-[8px] font-black text-slate-600 uppercase tracking-[0.4em] mt-1">Autopilot Active</p>
          </div>
        </div>

        <nav className="flex-grow py-8 px-4 space-y-1 overflow-y-auto">
          {[
            { id: 'overview', label: 'Command Center', icon: <LayoutDashboard size={18} /> },
            { id: 'autopilot', label: 'FIKO Autopilot', icon: <Zap size={18} />, badge: stats.autopilotActions.toString() },
            { id: 'leads', label: 'Asset Intelligence', icon: <Users size={18} /> },
            { id: 'security', label: 'Node Defense', icon: <ShieldCheck size={18} /> },
          ].map(item => (
            <button 
              key={item.id} 
              onClick={() => setActiveModule(item.id as AdminModule)} 
              className={`w-full flex items-center gap-4 px-6 py-4 rounded-sm transition-all relative ${
                activeModule === item.id ? 'bg-[#E10600] text-white' : 'text-slate-500 hover:text-white hover:bg-white/5'
              }`}
            >
              <span>{item.icon}</span>
              <span className="text-[10px] font-bold uppercase tracking-widest flex-grow text-left">{item.label}</span>
              {item.badge && <span className="text-[8px] font-black bg-black/30 px-2 py-0.5 rounded-sm">{item.badge}</span>}
            </button>
          ))}
        </nav>

        <div className="p-8 border-t border-white/5">
          <button onClick={onLogout} className="w-full flex items-center gap-4 px-4 text-slate-500 hover:text-red-500 transition-all text-[9px] font-black uppercase tracking-widest">
            <LogOut size={16} /> Déconnexion
          </button>
        </div>
      </aside>

      <main className="flex-grow flex flex-col overflow-hidden relative">
        <header className="h-20 bg-black/40 backdrop-blur-md border-b border-white/5 px-10 flex items-center justify-between z-40">
           <div className="flex items-center gap-8">
              <div className="flex items-center gap-3">
                 <div className="size-2 rounded-full bg-emerald-500 animate-pulse"></div>
                 <span className="text-[9px] font-black text-slate-400 uppercase tracking-[0.3em]">Autopilot: <span className="text-white">ON</span></span>
              </div>
              <div className="h-6 w-px bg-white/10"></div>
              <span className="text-[9px] font-black text-slate-600 uppercase tracking-[0.3em]">Inference Latency: <span className="text-white">14ms</span></span>
           </div>
        </header>

        <div className="flex-grow overflow-y-auto p-12 bg-[#0B0B0F]">
          <div className="max-w-[1600px] mx-auto pb-40">

            {activeModule === 'autopilot' && (
              <div className="space-y-12 animate-in fade-in duration-700">
                <div className="flex flex-col lg:flex-row justify-between items-start lg:items-end gap-8">
                   <div className="space-y-4">
                      <h2 className="text-6xl font-black uppercase tracking-tighter leading-none italic">FIKO <br/><span className="text-[#E10600] not-italic">AUTOPILOT.</span></h2>
                      <p className="text-[11px] font-black text-slate-500 uppercase tracking-[0.5em]">Surveillance en temps réel & Inférence de closing</p>
                   </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
                  {[
                    { label: 'Sessions Actives', val: leads.length.toString(), color: 'text-white' },
                    { label: 'Interventions MTD', val: '142', color: 'text-[#E10600]' },
                    { label: 'ROI Closing (Auto)', val: '28.4x', color: 'text-emerald-500' },
                    { label: 'Précision Trigger', val: '98.1%', color: 'text-blue-500' }
                  ].map((stat, i) => (
                    <div key={i} className="bg-[#14141A] p-10 border border-white/5 rounded-sm relative shadow-xl">
                      <p className="text-[10px] font-black uppercase tracking-widest text-slate-600 mb-8">{stat.label}</p>
                      <h3 className={`text-5xl font-black tracking-tighter ${stat.color}`}>{stat.val}</h3>
                    </div>
                  ))}
                </div>

                <div className="bg-[#14141A] border border-white/5 rounded-sm overflow-hidden shadow-2xl">
                   <div className="p-8 border-b border-white/5 bg-black/40 flex items-center justify-between">
                      <div className="flex items-center gap-4">
                         <Zap size={18} className="text-[#E10600]" />
                         <h3 className="text-[11px] font-black uppercase tracking-[0.4em]">PIPELINE DE DÉCISION AUTONOME</h3>
                      </div>
                   </div>
                   <div className="overflow-x-auto">
                      <table className="w-full text-left">
                         <thead>
                            <tr className="text-[9px] font-black text-slate-600 uppercase tracking-widest border-b border-white/5 bg-white/5">
                               <th className="px-8 py-6">IDENTITÉ</th>
                               <th className="px-8 py-6 text-center">STATUS AUTOPILOT</th>
                               <th className="px-8 py-6 text-center">LAST ACTION</th>
                               <th className="px-8 py-6 text-center">RISK</th>
                               <th className="px-8 py-6 text-right">INFÉRENCE</th>
                            </tr>
                         </thead>
                         <tbody className="divide-y divide-white/5">
                            {leads.map(l => (
                               <tr key={l.id} className="hover:bg-white/5 transition-colors group">
                                  <td className="px-8 py-8">
                                     <div>
                                        <p className="text-sm font-black text-white uppercase">{l.entity}</p>
                                        <p className="text-[9px] text-slate-500 uppercase font-bold mt-1">Porte: {l.gate}</p>
                                     </div>
                                  </td>
                                  <td className="px-8 py-8 text-center">
                                     <span className={`px-4 py-1.5 text-[9px] font-black border rounded-sm ${getStatusColor(l.autopilotState.status)}`}>
                                        {l.autopilotState.status}
                                     </span>
                                  </td>
                                  <td className="px-8 py-8 text-center">
                                     {l.autopilotState.lastDecision ? (
                                        <div className="flex flex-col items-center gap-1">
                                           <div className="flex items-center gap-2">
                                              {l.autopilotState.lastDecision.action === 'EMAIL' && <Mail size={12} className="text-blue-500"/>}
                                              {l.autopilotState.lastDecision.action === 'CHAT' && <MessageSquare size={12} className="text-[#E10600]"/>}
                                              {l.autopilotState.lastDecision.action === 'VOICE' && <Mic size={12} className="text-emerald-500"/>}
                                              <span className="text-[10px] font-black text-white">{l.autopilotState.lastDecision.action}</span>
                                           </div>
                                           <span className="text-[8px] text-slate-600 uppercase">{new Date(l.autopilotState.lastDecision.timestamp).toLocaleDateString()}</span>
                                        </div>
                                     ) : <span className="text-slate-700">NONE</span>}
                                  </td>
                                  <td className="px-8 py-8 text-center">
                                     <span className={`text-xs font-black ${l.riskLevel === 'CRITIQUE' ? 'text-[#E10600]' : 'text-white'}`}>{l.riskScore}%</span>
                                  </td>
                                  <td className="px-8 py-8 text-right">
                                     <button 
                                        onClick={() => runAutopilotInference(l)}
                                        disabled={isInferenceLoading === l.id}
                                        className="px-6 py-2 bg-white/5 border border-white/10 text-[9px] font-black uppercase tracking-widest hover:border-[#E10600] hover:bg-[#E10600]/10 transition-all flex items-center gap-3 ml-auto"
                                     >
                                        {isInferenceLoading === l.id ? <Loader2 size={12} className="animate-spin"/> : <Brain size={12}/>}
                                        {isInferenceLoading === l.id ? 'ANALYSIS...' : 'Run Inférence'}
                                     </button>
                                  </td>
                               </tr>
                            ))}
                         </tbody>
                      </table>
                   </div>
                </div>

                {/* MODAL / OVERLAY FOR LAST INFERENCE */}
                <AnimatePresence>
                   {lastInferenceResult && (
                      <motion.div 
                        initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }}
                        className="p-12 border border-[#E10600]/30 bg-black shadow-2xl relative overflow-hidden"
                      >
                         <div className="absolute top-0 right-0 p-12 opacity-5"><Bot size={150} /></div>
                         <div className="flex justify-between items-start mb-10">
                            <div className="space-y-2">
                               <p className="text-[#E10600] text-[10px] font-black uppercase tracking-[0.5em]">RÉSULTAT DÉCISIONNEL FIKO™</p>
                               <h3 className="text-3xl font-black uppercase tracking-tight">LOGIQUE DE CLOSING GÉNÉRÉE.</h3>
                            </div>
                            <button onClick={() => setLastInferenceResult(null)} className="text-slate-600 hover:text-white uppercase text-[10px] font-black">Fermer</button>
                         </div>

                         <div className="grid lg:grid-cols-2 gap-12 relative z-10">
                            <div className="space-y-8">
                               <div className="p-6 bg-white/5 border border-white/10">
                                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4">CANAL CHOISI : {lastInferenceResult.action}</p>
                                  <p className="text-xl font-light italic text-slate-300 leading-relaxed">
                                     « {lastInferenceResult.justification} »
                                  </p>
                               </div>
                            </div>
                            <div className="space-y-8">
                               <div className="p-6 bg-[#E10600]/5 border border-[#E10600]/30 relative overflow-hidden">
                                  <p className="text-[10px] font-black text-[#E10600] uppercase tracking-widest mb-4">MESSAGE GÉNÉRÉ</p>
                                  <p className="text-base text-white font-medium leading-relaxed">
                                     {lastInferenceResult.content || "Silence Stratégique Activé : aucune action immédiate requise."}
                                  </p>
                                  <div className="mt-8 flex gap-4">
                                     <button className="flex-grow py-4 bg-[#E10600] text-white font-black uppercase text-[9px] tracking-widest shadow-xl">Approuver & Envoyer</button>
                                     <button className="px-6 py-4 border border-white/10 text-slate-500 font-black uppercase text-[9px] tracking-widest">Ajuster</button>
                                  </div>
                               </div>
                            </div>
                         </div>
                      </motion.div>
                   )}
                </AnimatePresence>
              </div>
            )}

            {activeModule === 'overview' && (
               <div className="space-y-12 py-20 text-center animate-in fade-in duration-500">
                  <Hexagon size={120} className="mx-auto text-slate-800 mb-8" />
                  <h3 className="text-4xl font-black uppercase tracking-tighter">Bienvenue, Super Admin.</h3>
                  <p className="text-slate-500 uppercase tracking-widest text-xs">Le module Autopilot a été activé. 14 décisions en attente d'audit.</p>
                  <button onClick={() => setActiveModule('autopilot')} className="mt-12 px-12 py-6 bg-[#E10600] text-white font-black text-[10px] uppercase tracking-widest shadow-2xl">Ouvrir le Pilotage</button>
               </div>
            )}

          </div>
        </div>

        <footer className="h-16 border-t border-white/5 bg-[#08080A] px-10 flex items-center justify-between opacity-50 z-50">
           <div className="flex items-center gap-4">
              <div className="size-2 bg-emerald-500 rounded-full animate-pulse"></div>
              <p className="text-[10px] font-black uppercase tracking-[0.5em] text-slate-600">FIKO_AUTOPILOT_CORE_READY</p>
           </div>
        </footer>
      </main>
    </div>
  );
};

