const AgentsPage: React.FC<AgentsPageProps> = ({ onOpenFiko }) => {
  const [query, setQuery] = useState('');
  const [isAssembling, setIsAssembling] = useState(false);
  const [brief, setBrief] = useState<StrategicBrief | null>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  // Auto-resize logic for the strategic textarea
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${Math.max(104, textareaRef.current.scrollHeight)}px`;
    }
  }, [query]);

  const assembleSolution = async () => {
    if (!query.trim()) return;
    setIsAssembling(true);
    setBrief(null);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: `Conçois une unité stratégique Krypton AI pour le métier suivant : ${query}`,
        config: {
          systemInstruction: UNIVERSAL_DISCOVERY_PROMPT,
          responseMimeType: "application/json",
          // Fixed SchemaType usage to Type.OBJECT
          responseSchema: {
              type: Type.OBJECT,
              properties: {
                  solutionName: { type: Type.STRING },
                  sector: { type: Type.STRING },
                  description: { type: Type.STRING },
                  challenges: { type: Type.ARRAY, items: { type: Type.STRING } },
                  recommendedAgents: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["solutionName", "sector", "description", "challenges", "recommendedAgents"]
          },
          temperature: 0.8
        }
      });

      const result = JSON.parse(response.text || '{}');
      setBrief(result as StrategicBrief);
    } catch (error) {
      console.error('Neural Assembler Error:', error);
    } finally {
      setIsAssembling(false);
    }
  };

  const renderStatus = (status: Agent['status']) => {
    const config = {
      active: { color: 'bg-emerald-500', label: 'ACTIF' },
      standby: { color: 'bg-yellow-500', label: 'VEILLE' },
      deploying: { color: 'bg-blue-500', label: 'DÉPLOIEMENT' }
    };
    const { color, label } = config[status] || config.standby;

    return (
      <div className="flex items-center gap-2">
        <span className={`size-1.5 rounded-full ${color} animate-pulse shadow-[0_0_8px_rgba(0,0,0,0.5)]`}></span>
        <span className={`text-[8px] font-black tracking-widest uppercase text-slate-400 group-hover:text-white transition-colors`}>{label}</span>
      </div>
    );
  };

  return (
    <div className="max-w-7xl mx-auto px-6 pt-32 pb-32">
      <div className="text-center mb-24 relative">
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[600px] h-[600px] bg-red-600/10 blur-[150px] pointer-events-none rounded-full"></div>
        <div className="inline-flex items-center gap-3 px-6 py-2 border border-[#E10600]/30 bg-[#E10600]/5 rounded-sm mb-10">
           <BrainCircuit className="text-[#E10600]" size={16} />
           <span className="text-[10px] font-black uppercase tracking-[0.4em] text-[#E10600]">KRYPTON NEURAL ASSEMBLER v9.2</span>
        </div>
        <h1 className="text-5xl lg:text-8xl font-black tracking-tighter mb-10 uppercase relative z-10 leading-[0.9]">
          CONCEPTION IA <br/><span className="text-[#E10600] italic">SANS LIMITES.</span>
        </h1>
        <p className="text-slate-500 max-w-3xl mx-auto font-medium text-xl uppercase tracking-widest leading-relaxed relative z-10">
          Décrivez votre activité. <span className="text-white">Krypton AI</span> assemble et déploie l'unité stratégique exacte dont votre business a besoin.
        </p>
      </div>

      {/* Neural Discovery Bar - Dynamic Auto-Expanding UI */}
      <div className="max-w-4xl mx-auto mb-20 relative z-40">
        <div className="bg-[#1A1A1F]/90 backdrop-blur-3xl border border-white/10 p-2 rounded-sm shadow-[0_0_80px_rgba(0,0,0,0.5)] group flex flex-col sm:flex-row items-stretch gap-2 transition-all duration-500">
          <div className="relative flex-grow flex items-start">
            <Search className="absolute left-8 top-10 -translate-y-1/2 text-[#E10600] z-10" size={24} />
            <textarea 
              ref={textareaRef}
              rows={1}
              placeholder="DÉCRIVEZ VOTRE MÉTIER, VOTRE ACTIVITÉ OU VOTRE OBJECTIF..." 
              className="w-full bg-black border border-white/5 p-10 pl-20 pr-10 text-[14px] font-black uppercase tracking-[0.2em] text-white outline-none focus:border-[#E10600] transition-all placeholder:text-slate-800 resize-none overflow-hidden min-h-[104px]"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault();
                  assembleSolution();
                }
              }}
            />
          </div>
          <button 
            onClick={assembleSolution}
            disabled={isAssembling || !query.trim()}
            className="bg-[#E10600] text-white px-10 py-6 font-black text-xs uppercase tracking-[0.2em] hover:bg-red-700 transition-all shadow-xl shadow-red-500/20 disabled:opacity-50 disabled:cursor-not-allowed group/btn flex items-center justify-center min-w-[200px]"
          >
            {isAssembling ? <Loader2 className="animate-spin" size={20} /> : <span className="flex items-center gap-3">INITIALISER <ArrowRight size={16} className="group-hover/btn:translate-x-2 transition-transform" /></span>}
