           </div>
           <p className="text-[12px] font-black uppercase tracking-[0.6em] text-[#E10600]">Assemblage Neural de l'unité tactique...</p>
        </div>
      ) : brief ? (
        <div className="animate-in fade-in slide-in-from-bottom-12 duration-1000">
           <div className="grid lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2 bg-[#1A1A1F] border border-[#E10600]/30 p-16 rounded-sm shadow-2xl relative overflow-hidden group">
                 <div className="absolute top-0 right-0 p-12 opacity-[0.03] group-hover:scale-125 transition-transform duration-1000 pointer-events-none">
                    <Hexagon size={400} />
                 </div>
                 <div className="flex flex-col gap-10 relative z-10">
                    <div className="flex items-center gap-6">
                       <div className="size-20 bg-black border border-white/10 flex items-center justify-center rounded-sm text-[#E10600] shadow-2xl">
                          <Target size={40} />
                       </div>
                       <div>
                          <p className="text-[#E10600] text-[10px] font-black uppercase tracking-[0.5em] mb-2">{brief.sector}</p>
