                       </div>
                    </div>
                    <p className="text-2xl text-slate-400 font-light leading-relaxed italic border-l-2 border-[#E10600] pl-10 max-w-2xl">
                       "{brief.description}"
                    </p>
                    <div className="grid md:grid-cols-2 gap-10 pt-10 border-t border-white/5">
                       <div>
                          <h4 className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500 mb-6">Défis Stratégiques</h4>
                          <div className="space-y-4">
                             {brief.challenges.map((c, i) => (
                               <div key={i} className="flex items-start gap-4 text-white text-sm font-medium uppercase tracking-widest">
