    if (!autopilotEnabled) return;
    setIsInferenceLoading(lead.id);
    setLastInferenceResult(null);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `ÉTAT DU LEAD :
                   Nom: ${lead.entity}
                   Priority: ${lead.priorityScore}%
                   Risk: ${lead.riskScore}% (${lead.riskLevel})
                   Moment: ${lead.buyingMoment}
                   Dernier échange: ${new Date(lead.lastInteraction).toLocaleString()}

