import React, { useState, useEffect, useRef } from 'react';
import { Page, Message, Project, KryptonDocument, Transaction, KryptonNotification, UserProfile } from '../types';
import { FIKO_ONBOARDING_PROMPT, GATE_THEMES, MOCK_CLIENT_PROJECT, MOCK_CLIENT_DOCS, MOCK_NOTIFICATIONS, COLORS } from '../constants';
import { GoogleGenAI } from '@google/genai';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Hexagon, Activity, Clock, ShieldCheck, FileText, MessageSquare, 
  Bell, Rocket, Zap, Send, Bot, User, LayoutDashboard, LogOut, Download, 
  Target, TrendingUp, Sparkles, CreditCard, CheckCircle2, ChevronRight, 
  History, Building2, AlertCircle, Eye, Sliders, CheckSquare, Square, Info, 
  ArrowRight, Filter, MoreHorizontal, ExternalLink, Loader2, Trash2, 
  FileCode, Receipt, PieChart
} from 'lucide-react';
