interface ClientDashboardPageProps {
  onNavigate: (p: Page) => void;
  gate: string;
}

const ClientDashboardPage: React.FC<ClientDashboardPageProps> = ({ onNavigate, gate }) => {
  const theme = GATE_THEMES[gate] || GATE_THEMES.MARS;
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'overview' | 'project' | 'documents' | 'billing' | 'chat' | 'notifications'>('overview');

  const [project, setProject] = useState<Project>(MOCK_CLIENT_PROJECT);
  const [notifications, setNotifications] = useState<KryptonNotification[]>(MOCK_NOTIFICATIONS);
  const [messages, setMessages] = useState<Message[]>([]);
  const [fikoInsight, setFikoInsight] = useState<string>("Analyse des flux de données en cours...");

  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setTimeout(() => {
      setLoading(false);
      generateInitialFikoInsight();

      const savedMsgs = localStorage.getItem(`krypton_fiko_history_${gate}`);
      if (savedMsgs) setMessages(JSON.parse(savedMsgs));
      else {
          setMessages([{
              role: 'model',
              text: `Système Porte ${gate} opérationnel. Votre infrastructure IA est en phase de synchronisation. Souhaitez-vous un rapport d'étape ?`,
              timestamp: new Date().toLocaleTimeString()
          }]);
      }
    }, 1500);
    return () => clearTimeout(timer);
  }, [gate]);

  useEffect(() => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
    if (messages.length > 0) {
        localStorage.setItem(`krypton_fiko_history_${gate}`, JSON.stringify(messages));
    }
  }, [messages, isTyping]);

  const generateInitialFikoInsight = async () => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Génère un conseil stratégique ultra-court pour un dashboard client. Porte: ${gate}, Statut: ${project.status}, Progression: ${project.progress}%. Ton : Expert senior, direct.`,
        config: { systemInstruction: FIKO_ONBOARDING_PROMPT }
      });
      setFikoInsight(response.text || "Monitoring neural actif. Aucun écart détecté.");
    } catch (e) {
      setFikoInsight("Liaison FIKO stable. Diagnostic nominal en cours.");
    }
  };

  const handleSendChat = async () => {
    if (!input.trim() || isTyping) return;
    const userMsg = input;
    setInput('');
    const newMsgs = [...messages, { role: 'user', text: userMsg, timestamp: new Date().toLocaleTimeString() }] as Message[];
    setMessages(newMsgs);
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: newMsgs.map(m => ({ role: m.role, parts: [{ text: m.text }] })),
        config: { 
            systemInstruction: FIKO_ONBOARDING_PROMPT + `\nLe client opère en Porte ${gate}. Tu réponds avec autorité stratégique.`,
            temperature: 0.7
        }
      });
      setMessages([...newMsgs, { role: 'model', text: response.text || "Directive reçue.", timestamp: new Date().toLocaleTimeString() }]);
    } catch (e) {
      setMessages([...newMsgs, { role: 'model', text: "Liaison temporairement saturée. Données préservées.", timestamp: new Date().toLocaleTimeString() }]);
    } finally {
      setIsTyping(false);
    }
  };

  const markNotifRead = (id: string) => {
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, read: true } : n));
  };

  if (loading) return (
    <div className="min-h-screen bg-[#0B0B0F] flex flex-col items-center justify-center gap-10">
      <div className="relative">
        <Hexagon size={120} style={{ color: theme.color }} className="animate-[spin_10s_linear_infinite]" strokeWidth={1} />
        <div className="absolute inset-0 flex items-center justify-center">
           <Zap size={40} style={{ color: theme.color }} className="animate-pulse" />
        </div>
      </div>
      <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-600">Initialisation du cockpit...</p>
    </div>
  );

  return (
    <div className="min-h-screen bg-[#0B0B0F] text-white flex overflow-hidden font-sans selection:bg-[#E10600]">

      {/* 🛠 SIDEBAR */}
      <aside className="w-20 lg:w-80 bg-[#0A0A0C] border-r border-white/5 flex flex-col z-50">
        <div className="p-10 border-b border-white/5 flex items-center gap-4">
          <div className="size-12 bg-[#E10600] rounded-sm flex items-center justify-center shadow-xl">
            <Rocket size={24} className="text-white" />
          </div>
          <div className="hidden lg:block">
            <p className="font-black uppercase tracking-tighter text-2xl leading-none">KRYPTON <span className="text-[#E10600]">AI</span></p>
            <p className="text-[8px] font-black text-slate-600 uppercase tracking-[0.4em] mt-1">Dashboard Partenaire</p>
          </div>
        </div>

        <nav className="flex-grow py-10 px-6 space-y-2">
          {[
            { id: 'overview', label: 'Vue Globale', icon: <LayoutDashboard size={20} /> },
            { id: 'project', label: 'Suivi Projet', icon: <Target size={20} /> },
            { id: 'documents', label: 'Actifs & Docs', icon: <FileText size={20} /> },
            { id: 'billing', label: 'Facturation', icon: <CreditCard size={20} /> },
            { id: 'chat', label: 'Liaison FIKO™', icon: <MessageSquare size={20} /> },
            { id: 'notifications', label: 'Système', icon: <Bell size={20} />, badge: notifications.filter(n => !n.read).length }
          ].map(item => (
            <button 
              key={item.id} 
              onClick={() => setActiveTab(item.id as any)} 
              className={`w-full flex items-center gap-6 p-5 rounded-sm transition-all relative group ${
                activeTab === item.id ? 'bg-[#E10600] text-white shadow-xl shadow-red-900/20' : 'text-slate-500 hover:text-white hover:bg-white/5'
              }`}
            >
              <div className="relative">
                {item.icon}
                {item.badge ? (
                    <span className="absolute -top-2 -right-2 size-4 bg-[#E10600] text-white text-[8px] font-black flex items-center justify-center rounded-full border border-black">
                        {item.badge}
                    </span>
                ) : null}
              </div>
              <span className="hidden lg:block text-[11px] font-black uppercase tracking-[0.2em] flex-grow text-left">{item.label}</span>
            </button>
          ))}
        </nav>

        <div className="p-8 border-t border-white/5">
          <button onClick={() => onNavigate(Page.HOME)} className="w-full flex items-center gap-6 p-4 text-slate-500 hover:text-[#E10600] transition-all group">
            <LogOut size={20} className="group-hover:-translate-x-1 transition-transform" />
            <span className="hidden lg:block text-[11px] font-black uppercase tracking-widest">Quitter</span>
          </button>
        </div>
      </aside>

      {/* 🚀 MAIN CONTENT */}
      <main className="flex-grow flex flex-col overflow-hidden relative">
        <header className="h-24 bg-[#0B0B0F]/80 backdrop-blur-xl border-b border-white/5 px-10 flex items-center justify-between z-40">
           <div className="flex items-center gap-10">
              <div className={`px-5 py-2.5 border text-[10px] font-black uppercase tracking-[0.4em] rounded-full flex items-center gap-3`} style={{ backgroundColor: `${theme.color}15`, borderColor: `${theme.color}40`, color: theme.color }}>
                 <ShieldCheck size={14} className="animate-pulse" /> PORTE {gate} ACTIVE
              </div>
           </div>

           <div className="flex items-center gap-8">
              <div className="text-right hidden lg:block">
                 <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Partenaire</p>
                 <p className="text-xs font-bold text-white uppercase tracking-tighter">Utilisateur Krypton</p>
              </div>
              <div className="size-14 bg-white/5 border border-white/10 rounded-full flex items-center justify-center cursor-pointer hover:border-[#E10600]/50 transition-all">
                <User size={24} className="text-slate-400" />
              </div>
           </div>
        </header>

        <div className="flex-grow overflow-y-auto custom-scrollbar bg-[#0B0B0F] relative">
          <div className="absolute inset-0 hex-bg opacity-[0.03] pointer-events-none"></div>

          <div className="max-w-7xl mx-auto p-12 lg:p-16 space-y-16 pb-32 relative z-10">

            <AnimatePresence mode="wait">
              {/* LIAISON FIKO™ (CHAT) - REFACTORED FOR AUTOPILOT BADGES */}
              {activeTab === 'chat' && (
                <motion.div 
                  initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                  className="h-[700px] flex flex-col bg-black border border-white/10 rounded-sm relative overflow-hidden shadow-2xl"
                >
                  <div className="p-10 border-b border-white/10 bg-white/5 flex items-center justify-between relative z-10">
                    <div className="flex items-center gap-6">
                       <Bot size={40} className="text-[#E10600]" />
                       <div>
                          <p className="text-2xl font-black uppercase tracking-tighter leading-none">NOYAU FIKO™ CONNECTÉ</p>
                          <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mt-2">Canal Chiffré AES-512 Actif</p>
                       </div>
                    </div>
                  </div>

                  <div ref={scrollRef} className="flex-grow overflow-y-auto p-12 space-y-16 custom-scrollbar relative z-10">
                    {messages.map((m, i) => (
                      <div key={i} className={`flex ${m.role === 'model' ? 'justify-start' : 'justify-end'}`}>
                        <div className={`max-w-[75%] p-10 rounded-sm border relative ${
                            m.role === 'model' ? 'bg-[#121217] border-white/5 text-slate-300 font-light italic text-xl leading-relaxed' : 
                            'bg-[#E10600] border-[#E10600] text-white font-black uppercase tracking-widest text-sm'
                        }`}>
                          {m.role === 'model' && i > 0 && (
                            <div className="absolute -top-4 left-4 px-3 py-1 bg-[#E10600] text-white text-[8px] font-black uppercase tracking-[0.3em] rounded-sm flex items-center gap-2">
                               <Sparkles size={10} /> INTERVENTION STRATÉGIQUE
                            </div>
                          )}
                          {m.text}
                          <span className={`absolute -bottom-8 ${m.role === 'model' ? 'left-0' : 'right-0'} text-[9px] font-black text-slate-700 uppercase`}>{m.timestamp}</span>
                        </div>
                      </div>
                    ))}
                    {isTyping && (
                      <div className="flex justify-start">
                        <div className="bg-[#1A1A1F] p-8 border border-white/5 rounded-sm flex items-center gap-6 text-[#E10600]">
                           <Loader2 size={24} className="animate-spin" />
                           <span className="text-[13px] font-black uppercase tracking-[0.4em]">FIKO™ analyse votre directive...</span>
                        </div>
                      </div>
                    )}
                  </div>

                  <div className="p-12 border-t border-white/10 bg-black relative z-10">
                    <div className="max-w-5xl mx-auto relative group">
                       <input 
                         value={input} 
                         onChange={e => setInput(e.target.value)} 
                         onKeyDown={e => e.key === 'Enter' && handleSendChat()} 
                         placeholder="TRANSMETTRE UNE DIRECTIVE..." 
                         className="w-full bg-[#121217] border border-white/5 p-10 pr-24 text-[16px] font-black uppercase tracking-[0.3em] text-white outline-none focus:border-[#E10600] transition-all" 
                       />
                       <button onClick={handleSendChat} disabled={isTyping || !input.trim()} className="absolute right-8 top-1/2 -translate-y-1/2 text-[#E10600] hover:scale-110 transition-transform">
                          <Send size={40} />
                       </button>
                    </div>
                  </div>
                </motion.div>
              )}

              {/* OTHERS TABS STAYS THE SAME ... */}
              {activeTab === 'overview' && (
                <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-12">
                   {/* Rest of the overview code exactly as before */}
                   <div className="bg-[#1A1A1F] p-12 border border-white/5 rounded-sm relative overflow-hidden flex flex-col lg:flex-row justify-between items-center gap-12 shadow-2xl">
                     <div className="absolute top-0 left-0 w-2 h-full" style={{ backgroundColor: theme.color }}></div>
                     <div className="space-y-8 flex-grow relative z-10">
                        <div className="space-y-2">
                           <p className="text-[11px] font-black uppercase tracking-[0.6em] text-slate-600">ID PROJET — {project.id}</p>
                           <h2 className="text-6xl font-black uppercase tracking-tighter leading-none">{project.name}</h2>
                        </div>
                        <div className="flex items-center gap-4 bg-black/40 border border-white/5 p-4 rounded-sm">
                           <Bot size={24} className="text-[#E10600]" />
                           <p className="text-lg text-slate-300 font-light italic">« {fikoInsight} »</p>
                        </div>
                     </div>
                     <div className="flex flex-col items-center gap-6 min-w-[320px] relative z-10">
                        <div className="flex items-end gap-3">
                           <span className="text-8xl font-black tracking-tighter leading-none" style={{ color: theme.color }}>{project.progress}</span>
