  const runAutopilotInference = async (lead: Lead) => {
    if (!autopilotEnabled) return;
    setIsInferenceLoading(lead.id);
    setLastInferenceResult(null);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `ANALYSE DU LEAD POUR DÉCISION AUTOPILOT :
                   Entité: ${lead.entity}
                   Score Priorité: ${lead.priorityScore}%
                   Risque: ${lead.riskScore}%
                   Moment: ${lead.buyingMoment}
                   Inactivité: 42h

                   DÉCIDE DE L'ACTION STRATÉGIQUE (JSON).`,
        config: { 
          systemInstruction: FIKO_AUTOPILOT_MASTER_PROMPT,
          responseMimeType: "application/json"
        }
      });

      const decision: AutopilotDecision = {
        id: `D-${Date.now()}`,
        timestamp: new Date().toISOString(),
        signal: 'MANUAL_TRIGGER',
        status: 'EXECUTED',
        ...JSON.parse(response.text || "{}")
