      setLastInferenceResult(decision);
      setLeads(prev => prev.map(l => l.id === lead.id ? {
        ...l,
        autopilotState: {
          ...l.autopilotState,
          status: decision.action === 'SILENCE' ? 'SILENCE_STRATÉGIQUE' : 'INTERVENTION',
          lastDecision: decision,
          sessionHistory: [decision, ...l.autopilotState.sessionHistory]
