interface AdminDashboardPageProps {
  onNavigate: (p: Page) => void;
  user: UserProfile | null;
  onLogout: () => void;
}

type AdminModule = 'command' | 'autopilot' | 'assets' | 'nodes' | 'security';
type AssetFilter = 'all' | 'prospects' | 'clients' | 'hot';

const AdminDashboardPage: React.FC<AdminDashboardPageProps> = ({ onNavigate, user, onLogout }) => {
  const [loading, setLoading] = useState(true);
  const [activeModule, setActiveModule] = useState<AdminModule>('command');
  const [leads, setLeads] = useState<Lead[]>(LEADS);
  const [searchQuery, setSearchQuery] = useState('');
  const [assetFilter, setAssetFilter] = useState<AssetFilter>('all');
  const [isInferenceLoading, setIsInferenceLoading] = useState<string | null>(null);
  const [lastInferenceResult, setLastInferenceResult] = useState<AutopilotDecision | null>(null);
  const [autopilotEnabled, setAutopilotEnabled] = useState(true);

  useEffect(() => {
    if (user?.role !== UserRole.SUPER_ADMIN && user?.role !== UserRole.ADMIN) {
      onNavigate(Page.HOME);
    }
    const timer = setTimeout(() => setLoading(false), 1200);
    return () => clearTimeout(timer);
  }, [user, onNavigate]);

  const stats = useMemo(() => ({
    revenueTotal: "4.82B FCFA",
    recoveredByIA: "1.24B FCFA",
    conversionRate: "31.2%",
    activeNodes: 142,
    totalProspects: leads.filter(l => l.status !== 'client').length,
    totalClients: leads.filter(l => l.status === 'client').length
  }), [leads]);

  const filteredLeads = useMemo(() => {
    return leads.filter(l => {
      const matchesSearch = l.entity.toLowerCase().includes(searchQuery.toLowerCase()) || l.email.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesFilter = 
        assetFilter === 'all' ? true :
        assetFilter === 'clients' ? l.status === 'client' :
        assetFilter === 'prospects' ? l.status !== 'client' :
        assetFilter === 'hot' ? l.status === 'hot' : true;
      return matchesSearch && matchesFilter;
    });
  }, [leads, searchQuery, assetFilter]);

  const runAutopilotInference = async (lead: Lead) => {
    if (!autopilotEnabled) return;
    setIsInferenceLoading(lead.id);
    setLastInferenceResult(null);

    try {
      // Create new GoogleGenAI instance per guideline for latest API key
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `ANALYSE DU LEAD POUR DÉCISION AUTOPILOT :
                   Entité: ${lead.entity}
                   Score Priorité: ${lead.priorityScore}%
                   Risque: ${lead.riskScore}%
                   Moment: ${lead.buyingMoment}
                   Inactivité: 42h

                   DÉCIDE DE L'ACTION STRATÉGIQUE (JSON).`,
        config: { 
          systemInstruction: FIKO_AUTOPILOT_MASTER_PROMPT,
          responseMimeType: "application/json"
        }
      });

      const decision: AutopilotDecision = {
        id: `D-${Date.now()}`,
        timestamp: new Date().toISOString(),
        signal: 'MANUAL_TRIGGER',
        status: 'EXECUTED',
        ...JSON.parse(response.text || "{}")
      };

      setLastInferenceResult(decision);
      setLeads(prev => prev.map(l => l.id === lead.id ? {
        ...l,
        autopilotState: {
          ...l.autopilotState,
          status: decision.action === 'SILENCE' ? 'SILENCE_STRATÉGIQUE' : 'INTERVENTION',
          lastDecision: decision,
          sessionHistory: [decision, ...l.autopilotState.sessionHistory]
        }
      } : l));
    } catch (e) {
      console.error("Inference Engine Failure", e);
    } finally {
      setIsInferenceLoading(null);
    }
  };

