import React, { useState, useRef, useEffect } from 'react';
import { MASTER_AGENTS, UNIVERSAL_DISCOVERY_PROMPT } from '../constants';
import { 
  Search, Hexagon, Mic, Bolt, BrainCircuit, Activity, Sparkles, Loader2, ArrowRight, Target, ShieldCheck
} from 'lucide-react';
import { GoogleGenAI, Type } from '@google/genai';
import { Agent, StrategicBrief } from '../types';
import { motion, AnimatePresence } from 'framer-motion';

interface AgentsPageProps {
  onOpenFiko: () => void;
}

const AgentsPage: React.FC<AgentsPageProps> = ({ onOpenFiko }) => {
  const [query, setQuery] = useState('');
  const [isAssembling, setIsAssembling] = useState(false);
  const [brief, setBrief] = useState<StrategicBrief | null>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${Math.max(80, textareaRef.current.scrollHeight)}px`;
    }
  }, [query]);

  const assembleSolution = async () => {
    if (!query.trim()) return;
    setIsAssembling(true);
    setBrief(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: `Conçois une unité stratégique Krypton AI pour le métier suivant : ${query}. Version 1.2 active.`,
        config: {
          systemInstruction: UNIVERSAL_DISCOVERY_PROMPT,
          responseMimeType: "application/json",
          responseSchema: {
              type: Type.OBJECT,
              properties: {
                  solutionName: { type: Type.STRING },
                  sector: { type: Type.STRING },
                  description: { type: Type.STRING },
                  challenges: { type: Type.ARRAY, items: { type: Type.STRING } },
                  recommendedAgents: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["solutionName", "sector", "description", "challenges", "recommendedAgents"]
          },
          temperature: 0.8
        }
      });
      const result = JSON.parse(response.text || '{}');
      setBrief(result as StrategicBrief);
    } catch (error) {
      console.error('Neural Assembler Error:', error);
    } finally {
      setIsAssembling(false);
    }
  };

  const renderStatus = (status: Agent['status']) => {
    const config = {
      active: { color: 'bg-emerald-500', label: 'OPÉRATIONNEL' },
      standby: { color: 'bg-yellow-500', label: 'VEILLE' },
      deploying: { color: 'bg-blue-500', label: 'DÉPLOIEMENT' }
    };
    const { color, label } = config[status] || config.standby;
    return (
      <div className="flex items-center gap-2">
        <span className={`size-1.5 rounded-full ${color} animate-pulse shadow-[0_0_8px_rgba(225,6,0,0.4)]`}></span>
        <span className="text-[8px] font-black tracking-widest text-slate-400 uppercase">{label}</span>
      </div>
    );
  };

  return (
    <div className="bg-[#0B0B0F] min-h-screen relative overflow-hidden">
      <div className="absolute inset-0 hex-bg opacity-[0.03] pointer-events-none"></div>
      <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[800px] h-[800px] bg-[#E10600]/5 blur-[180px] pointer-events-none rounded-full"></div>

      <div className="max-w-7xl mx-auto px-6 pt-32 pb-40 relative z-10">

        <div className="text-center mb-24 animate-in fade-in slide-in-from-bottom-4 duration-700">
          <div className="inline-flex items-center gap-3 px-6 py-2 border border-[#E10600]/30 bg-[#E10600]/5 rounded-sm mb-10">
             <BrainCircuit className="text-[#E10600]" size={16} />
             <span className="text-[10px] font-black uppercase tracking-[0.4em] text-[#E10600]">ARSENAL D'INTELLIGENCE V1.2</span>
          </div>
          <h1 className="text-6xl lg:text-9xl font-black tracking-tighter mb-8 uppercase leading-[0.9]">
            UNITÉS <br/><span className="text-[#E10600] italic">TACTIQUES.</span>
          </h1>
          <p className="text-slate-500 max-w-3xl mx-auto font-medium text-xl uppercase tracking-widest leading-relaxed">
            Déployez des experts autonomes conçus pour <span className="text-white">dominer votre marché</span>. 
          </p>
        </div>

        <div className="max-w-4xl mx-auto mb-32 relative group">
          <div className="bg-[#1A1A1F]/90 backdrop-blur-3xl border border-white/10 p-2 rounded-sm shadow-[0_0_80px_rgba(0,0,0,0.5)] flex flex-col sm:flex-row items-stretch gap-2 transition-all duration-500 group-hover:border-[#E10600]/40">
            <div className="relative flex-grow flex items-start">
              <Search className="absolute left-8 top-1/2 -translate-y-1/2 text-[#E10600] z-10" size={24} />
              <textarea 
                ref={textareaRef}
                rows={1}
                placeholder="BESOIN D'UNE UNITÉ SUR MESURE ? DÉCRIVEZ VOTRE MÉTIER..." 
                className="w-full bg-black border border-white/5 p-8 pl-20 text-sm font-black uppercase tracking-widest text-white outline-none focus:border-[#E10600] transition-all placeholder:text-slate-800 resize-none overflow-hidden min-h-[80px]"
                value={query}
                onChange={(e) => setQuery(e.target.value)}
              />
            </div>
            <button 
              onClick={assembleSolution}
              disabled={isAssembling || !query.trim()}
              className="bg-[#E10600] text-white px-10 py-6 font-black text-xs uppercase tracking-[0.3em] hover:bg-red-700 transition-all flex items-center justify-center min-w-[200px] group/btn active:scale-95"
            >
              {isAssembling ? <Loader2 className="animate-spin" size={20} /> : <span>ASSEMBLER <ArrowRight size={16} className="inline ml-2 group-hover/btn:translate-x-2 transition-transform" /></span>}
            </button>
          </div>
        </div>

        <AnimatePresence>
          {brief && (
            <motion.div 
              initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }}
              className="mb-32 bg-[#1A1A1F] border border-[#E10600]/30 p-12 lg:p-20 rounded-sm shadow-2xl relative overflow-hidden group"
            >
              <div className="absolute top-0 right-0 p-12 opacity-[0.03] group-hover:scale-110 transition-transform duration-1000"><Hexagon size={400} /></div>
              <div className="flex flex-col lg:flex-row gap-16 relative z-10">
                <div className="flex-grow space-y-8">
                  <div className="flex items-center gap-6">
                    <div className="size-20 bg-black border border-white/10 flex items-center justify-center rounded-sm text-[#E10600]"><Target size={40} /></div>
                    <div>
                      <p className="text-[#E10600] text-[10px] font-black uppercase tracking-[0.5em] mb-2">{brief.sector}</p>
                      <h2 className="text-4xl lg:text-6xl font-black uppercase tracking-tighter leading-none">{brief.solutionName}</h2>
                    </div>
                  </div>
                  <p className="text-2xl text-slate-400 font-light italic leading-relaxed border-l border-[#E10600] pl-8">"{brief.description}"</p>
                  <div className="grid md:grid-cols-2 gap-10 pt-8 border-t border-white/5">
                     <div>
                        <h4 className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500 mb-6">Objectifs de Déploiement</h4>
                        <div className="space-y-4">
                           {brief.challenges.map((c, i) => (
                             <div key={i} className="flex items-center gap-4 text-white text-xs font-bold uppercase tracking-widest">
                                <div className="size-1.5 bg-[#E10600] rounded-full"></div> {c}
                             </div>
                           ))}
                        </div>
                     </div>
                     <div className="flex flex-col justify-end">
                        <button onClick={onOpenFiko} className="w-full bg-white text-black py-8 font-black uppercase text-[10px] tracking-[0.4em] hover:bg-[#E10600] hover:text-white transition-all shadow-xl flex items-center justify-center gap-4">
                           INITIALISER L'UNITÉ <Mic size={18} />
                        </button>
                     </div>
                  </div>
                </div>
              </div>
            </motion.div>
          )}
        </AnimatePresence>

        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
          {MASTER_AGENTS.map((agent, i) => (
            <motion.div 
              key={agent.id}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.1 }}
              className="bg-[#1A1A1F] border border-white/5 group hover:border-[#E10600]/40 transition-all duration-500 flex flex-col relative overflow-hidden shadow-xl"
            >
              <div className="relative h-64 overflow-hidden border-b border-white/5">
                <img 
                  src={(agent as any).image} 
                  alt={agent.name} 
                  className="w-full h-full object-cover grayscale brightness-50 group-hover:scale-105 group-hover:grayscale-0 transition-all duration-700 opacity-60 group-hover:opacity-100" 
                />
                <div className="absolute inset-0 bg-gradient-to-t from-[#1A1A1F] to-transparent"></div>
                <div className="absolute top-6 right-6 z-20">
                   {renderStatus(agent.status as any)}
                </div>
                <div className="absolute bottom-6 left-8">
                   <span className="px-3 py-1 bg-[#E10600] text-white text-[8px] font-black uppercase tracking-widest rounded-sm">{agent.sector}</span>
                </div>
              </div>

              <div className="p-10 flex flex-col flex-grow">
                <div className="flex items-center justify-between mb-6">
                   <h3 className="text-2xl font-black uppercase tracking-tight group-hover:text-[#E10600] transition-colors">{agent.name}</h3>
                   <Bolt size={18} className="text-[#E10600] opacity-30 group-hover:opacity-100 transition-opacity" />
                </div>
                <p className="text-slate-400 text-sm leading-relaxed mb-10 font-light italic flex-grow">
                  {agent.description}
                </p>
                <div className="pt-8 border-t border-white/5 flex flex-col gap-4">
                  <div className="flex justify-between text-[8px] font-black text-slate-600 uppercase tracking-widest">
                     <span>Précision : 99.4%</span>
                     <span>Inférence : &lt;14ms</span>
                  </div>
                  <button 
                    onClick={onOpenFiko}
                    className="w-full py-6 bg-white/5 border border-white/10 text-white text-[10px] uppercase font-black tracking-[0.4em] hover:bg-[#E10600] hover:border-[#E10600] transition-all flex items-center justify-center gap-4 group/btn"
                  >
                    Déployer l'unité <ArrowRight size={14} className="group-hover/btn:translate-x-2 transition-transform" />
                  </button>
                </div>
              </div>

              <div className="absolute -bottom-4 -right-4 size-24 opacity-[0.02] group-hover:opacity-[0.05] transition-opacity pointer-events-none">
                <Hexagon size={100} />
              </div>
            </motion.div>
          ))}
        </div>

      </div>
    </div>
  );
};

