function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

interface VocalSalesOverlayProps {
  agent: Agent | null;
  onClose: () => void;
  onOpenCheckout: (porte: string) => void;
  initialPorte?: string;
  initialFlowStep?: FikoFlowStep;
}

const VocalSalesOverlay: React.FC<VocalSalesOverlayProps> = ({ agent, onClose, onOpenCheckout, initialPorte }) => {
  const [step, setStep] = useState<'pre_start' | 'connecting' | 'active'>('pre_start');
  const [bars, setBars] = useState<number[]>(new Array(40).fill(5));

  // MODULE 4 ML ENGINE STATE
  const [priorityScore, setPriorityScore] = useState(0);
  const [decisionScore, setDecisionScore] = useState(0);
  const [fakeDecisionScore, setFakeDecisionScore] = useState(0);
  const [buyingMoment, setBuyingMoment] = useState<BuyingWindow>(BuyingWindow.LATER);
  const [ltvClass, setLtvClass] = useState<LTVClass>(LTVClass.BRONZE);
  const [transcription, setTranscription] = useState("");

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // MODULE 4 : VERTEX AI INFERENCE SIMULATION ENGINE
  useEffect(() => {
    if (!transcription) return;
    const text = transcription.toLowerCase();

    // ANALYSE LINGUISTIQUE TEMPS RÉEL (Signaux du Module 4)
    const hasI = (text.match(/\b(je|moi|mon|ma|mes)\b/g) || []).length;
    const hasWe = (text.match(/\b(nous|on|équipe|direction|comité)\b/g) || []).length;
    const hasNow = text.includes("maintenant") || text.includes("urgent") || text.includes("prix") || text.includes("virement");
    const hasComplexity = text.includes("automatisation") || text.includes("architecture") || text.includes("infrastructure");

    setDecisionScore(prev => Math.min(100, Math.max(0, prev + (hasI * 12) - (hasWe * 5))));

    if (text.includes("en parler à") || text.includes("réfléchir") || text.includes("plus tard")) {
      setFakeDecisionScore(prev => Math.min(100, prev + 20));
    }

    if (hasNow) setBuyingMoment(BuyingWindow.NOW);
    if (hasComplexity) setLtvClass(LTVClass.GOLD);
    if (hasComplexity && (text.includes("groupe") || text.includes("international"))) setLtvClass(LTVClass.PLATINUM);

    // CALCUL DU SCORE PRIORITÉ COMBINÉ (Cerveau du Module 3)
    const calcPriority = () => {
      const dWeight = decisionScore * 0.35;
      const bWeight = (buyingMoment === BuyingWindow.NOW ? 100 : 30) * 0.35;
      const lWeight = (ltvClass === LTVClass.PLATINUM ? 100 : ltvClass === LTVClass.GOLD ? 70 : 40) * 0.3;
      const fPenalty = fakeDecisionScore * 0.25;
      return Math.max(0, Math.min(100, Math.round(dWeight + bWeight + lWeight - fPenalty)));
    };

    setPriorityScore(calcPriority());
  }, [transcription, decisionScore, fakeDecisionScore, buyingMoment, ltvClass]);

  const stopSession = useCallback(() => {
    setStep('pre_start');
    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();
    inputAudioContextRef.current?.close();
    outputAudioContextRef.current?.close();
    if (sessionRef.current) sessionRef.current.close();
    sessionRef.current = null;
  }, []);

  const startVocalSession = async () => {
    setStep('connecting');
    try {
      const AudioContextClass = (window as any).AudioContext || (window as any).webkitAudioContext;
      const inputCtx = new AudioContextClass({ sampleRate: 16000 });
      const outputCtx = new AudioContextClass({ sampleRate: 24000 });

      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
