  const [isInferenceLoading, setIsInferenceLoading] = useState<string | null>(null);

  useEffect(() => {
    if (user?.role !== UserRole.SUPER_ADMIN && user?.role !== UserRole.ADMIN) {
      onNavigate(Page.HOME);
    }
    const timer = setTimeout(() => setLoading(false), 1500);
