      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `ANALYSE DU LEAD POUR DÉCISION AUTOPILOT : Entité: ${lead.entity}, Score: ${lead.priorityScore}%. DÉCIDE JSON.`,
        config: { systemInstruction: FIKO_AUTOPILOT_MASTER_PROMPT, responseMimeType: "application/json" }
      });

      const decision: AutopilotDecision = {
        id: `D-${Date.now()}`,
        timestamp: new Date().toISOString(),
        signal: 'MANUAL_TRIGGER',
        status: 'EXECUTED',
        ...JSON.parse(response.text || "{}")
      };

      setLeads(prev => prev.map(l => l.id === lead.id ? {
        ...l,
        autopilotState: {
          ...l.autopilotState,
          status: decision.action === 'SILENCE' ? 'SILENCE_STRATÉGIQUE' : 'INTERVENTION',
          lastDecision: decision,
          sessionHistory: [decision, ...l.autopilotState.sessionHistory]
