        { label: "Outils Disparates", value: "messy", boost: 15 },
        { label: "Système Obsolete", value: "old", boost: 20 }
      ]
    },
    [FikoState.AXE_FRICTIONS]: {
      text: "C'est un point critique. Qu'est-ce qui vous fait perdre le plus de temps ou d'opportunités actuellement ?",
      actions: [
        { label: "Qualification Leads", value: "leads", boost: 20 },
