    },
    [FikoState.AXE_URGENCE]: {
      text: "L'impact est identifié. À quel point la résolution de ce blocage est-elle prioritaire pour votre direction ?",
      actions: [
        { label: "Priorité Absolue", value: "urgent", boost: 25 },
        { label: "Sous 30 jours", value: "medium", boost: 10 },
        { label: "En observation", value: "low", boost: 5 }
      ]
    },
    [FikoState.AXE_COMPLEXITE]: {
      text: "Dernière précision : parle-t-on d'un besoin ponctuel ou d'une infrastructure robuste pour dominer votre secteur ?",
      actions: [
        { label: "Simple & Rapide", value: "light", boost: 10 },
        { label: "Système Structuré", value: "robust", boost: 15 },
        { label: "Souveraineté IA", value: "total", boost: 20 }
      ]
    },
    [FikoState.RECOMMANDATION]: {
      text: `D'après notre échange, la PORTE ${recommendedGate || 'MARS'} est la seule décision logique pour vous. Je vais vous expliquer pourquoi.`,
      actions: [
        { label: "Détaillez la stratégie", value: "explain", boost: 5 }
      ]
    },
    [FikoState.GATE_OPENING]: {
      text: "C'est la décision d'un dirigeant averti. Je vous ouvre l'accès au Portal Gate immédiatement.",
      actions: [
        { label: "FRANCHIR LA PORTE", value: "enter", boost: 5 }
      ]
    }
  };

  const speakWithGemini = useCallback(async (text: string) => {
    if (!voiceEnabled) return;
    if (currentSourceRef.current) {
        try { currentSourceRef.current.stop(); } catch(e) {}
    }

    setIsSpeaking(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      // CRITICAL FIX: The TTS model expects a simple prompt to generate strictly audio. 
      // Complex instructional prompts often cause it to return text parts, which fails when only Modality.AUDIO is requested.
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: `Say this in a calm, authoritative and senior strategic tone: ${text}` }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: 'Kore' },
            },
          },
          // We move the persona instruction here if supported, but most importantly simplify the 'text' to speak.
          systemInstruction: "You are FIKO, a senior strategic sales consultant for Krypton AI. Your tone is peer-to-peer, authoritative, and visionary."
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) {
        if (!audioContextRef.current || audioContextRef.current.state === 'closed') {
          audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        }
        if (audioContextRef.current.state === 'suspended') await audioContextRef.current.resume();

        const audioBuffer = await decodeAudioData(decode(base64Audio), audioContextRef.current, 24000, 1);
        const source = audioContextRef.current.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(audioContextRef.current.destination);
        source.onended = () => { 
            setIsSpeaking(false); 
            if (currentSourceRef.current === source) currentSourceRef.current = null; 
        };
        currentSourceRef.current = source;
        source.start();
      } else {
          setIsSpeaking(false);
      }
    } catch (error) {
      console.error("TTS Gemini Error:", error);
      setIsSpeaking(false);
    }
  }, [voiceEnabled]);

  useEffect(() => {
    if (state === FikoState.INITIALIZING) {
      setTimeout(() => setState(FikoState.AXE_OBJECTIF), 2200);
