    speakWithGemini(currentScript.text);

    let i = 0;
    const interval = setInterval(() => {
      setDisplayedText((prev) => prev + currentScript.text.charAt(i));
      i++;
      if (i >= currentScript.text.length) {
        clearInterval(interval);
        setIsTyping(false);
      }
    }, 28);

    return () => {
      clearInterval(interval);
      if (currentSourceRef.current) {
          try { currentSourceRef.current.stop(); } catch(e) {}
