        setRecommendedGate("TERRA");
        textToDisplay = "Parfait. Dans votre cas, un site passif vous fait perdre de l’argent tous les jours. Je vous recommande la Porte TERRA : un agent IA commercial opérationnel immédiatement pour ne plus rater aucun client.";
