        <button onClick={() => onNavigate(Page.HOME)} className="flex items-center gap-4 text-[10px] font-black uppercase tracking-[0.5em] text-slate-500 hover:text-white transition-all">
          <ArrowLeft size={16} /> Interrompre Audit
        </button>
        <div className="flex items-center gap-8">
           <div className={`px-4 py-1.5 border transition-all duration-500 ${isSpeaking ? 'shadow-[0_0_15px_rgba(225,6,0,0.2)]' : 'border-white/10 text-slate-500'}`} style={{ 
             borderColor: isSpeaking ? activeColor : 'rgba(255,255,255,0.1)',
             backgroundColor: isSpeaking ? `${activeColor}10` : 'transparent',
             color: isSpeaking ? activeColor : undefined
           }}>
              <span className="text-[8px] font-black uppercase tracking-widest">FIKO_LIVE_V1.001</span>
           </div>
           <button onClick={() => setVoiceEnabled(!voiceEnabled)} className={`size-12 rounded-full flex items-center justify-center border transition-all ${voiceEnabled ? 'border-[#E10600] text-[#E10600]' : 'border-white/10 text-slate-500'}`}>
             {voiceEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}
           </button>
        </div>
      </header>

      <main className="flex-grow flex flex-col items-center justify-center p-6 lg:p-20 relative z-10">
        <div className="max-w-6xl w-full grid lg:grid-cols-2 gap-20 items-center">

          {/* VISUAL CORE */}
          <div className="flex flex-col items-center gap-12">
            <div className="relative">
              <div 
                className={`size-80 lg:size-[450px] rounded-full border-2 flex items-center justify-center transition-all duration-700 ${isSpeaking ? 'animate-[pulse_4s_infinite]' : 'border-white/5'}`}
                style={{ 
                  borderColor: isSpeaking ? `${activeColor}44` : 'rgba(255,255,255,0.05)',
                  boxShadow: isSpeaking ? `0 0 100px ${activeColor}22` : 'none',
                  backgroundColor: isSpeaking ? `${activeColor}05` : 'transparent'
                }}
              >
                <div className="flex flex-col items-center relative">
                  {/* Hexagon with breathing and rotating animation */}
                  <Hexagon 
                    size={120} 
                    className={`transition-all duration-700 ${isSpeaking ? 'animate-fiko-active' : 'text-slate-800'}`} 
                    style={{ color: isSpeaking ? activeColor : undefined }}
                    strokeWidth={1} 
                  />

                  {/* Decorative glow ring when speaking */}
                  {isSpeaking && (
                    <div className="absolute inset-0 border border-white/10 rounded-full scale-150 animate-ping opacity-20" style={{ borderColor: activeColor }}></div>
                  )}

                  <h2 className="text-4xl font-black text-white uppercase mt-10 tracking-[0.2em] neon-fiko">FIKO™</h2>
                </div>
              </div>
              <div className="absolute -bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-4 px-8 py-4 bg-[#1A1A1F] border border-white/10 shadow-2xl">
                 <Activity size={16} className={isSpeaking ? "animate-pulse" : "text-slate-700"} style={{ color: isSpeaking ? activeColor : undefined }} />
                 <span className="text-[10px] font-black uppercase tracking-[0.3em]" style={{ color: isSpeaking ? activeColor : undefined }}>
                   {isSpeaking ? "ANALYSE STRATÉGIQUE..." : "VEILLE ACTIVE"}
                 </span>
              </div>
            </div>
          </div>

          {/* SCRIPT INTERFACE */}
          <div className="flex flex-col gap-12">
             <div 
                className="bg-[#1A1A1F]/80 p-12 lg:p-16 border-l-4 shadow-2xl min-h-[350px] flex flex-col justify-center transition-colors duration-700"
                style={{ borderLeftColor: isSpeaking ? activeColor : '#E10600' }}
             >
                <p className="text-2xl lg:text-4xl text-white font-light italic leading-tight">
                  {displayedText || "..."}
                  {isTyping && <span className="inline-block w-1.5 h-10 ml-2 animate-pulse" style={{ backgroundColor: activeColor }}></span>}
                </p>
             </div>

             <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                {!isTyping && scripts[step]?.actions.map((action, i) => (
                  <button 
                    key={i} 
                    onClick={() => handleAction(action)}
                    className="p-6 bg-white/5 border border-white/10 hover:bg-[#E10600]/10 text-center transition-all group active:scale-95"
                    style={{ '--hover-border': activeColor } as any}
                  >
                    <span className="text-[10px] font-black uppercase tracking-widest text-slate-500 group-hover:text-white transition-colors">{action.label}</span>
                  </button>
                ))}
             </div>

             {/* HUD STATUS */}
             <div className="grid grid-cols-2 gap-6 pt-10 border-t border-white/5">
                <div>
                   <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest mb-1">MATURITÉ DÉCISIONNELLE</p>
                   <div className="flex items-end gap-3">
                      <span className="text-3xl font-black text-white">{maturityScore}</span>
                      <span className="text-[10px] text-slate-700 font-bold mb-1.5">%</span>
                   </div>
                </div>
                <div>
                   <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest mb-1">PORTE ESTIMÉE</p>
                   <span className="text-xl font-black uppercase tracking-tighter" style={{ color: activeColor }}>
                      {recommendedGate}
                   </span>
                </div>
             </div>
          </div>

        </div>
      </main>

      <footer className="absolute bottom-8 w-full px-10 flex justify-between items-center pointer-events-none opacity-30">
        <p className="text-[8px] font-black uppercase tracking-widest text-slate-600">GOOGLE ADS OPTIMIZED FLOW // KRYPTON AI SYSTEMS</p>
        <p className="text-[8px] font-black uppercase tracking-widest text-slate-600">V1.001 [LOCKED]</p>
      </footer>

      <style>{`
        @keyframes fiko-active {
          0% { transform: scale(1) rotate(0deg); filter: brightness(1); }
          50% { transform: scale(1.1) rotate(180deg); filter: brightness(1.4) drop-shadow(0 0 15px currentColor); }
          100% { transform: scale(1) rotate(360deg); filter: brightness(1); }
        }
        .animate-fiko-active {
          animation: fiko-active 6s ease-in-out infinite;
        }
        button:hover {
          border-color: var(--hover-border, #E10600);
        }
      `}</style>
    </div>
  );
};

export default FikoPage;
